3.2 调度类裁剪：资源受限设备优化

嵌入式超小资源设备（如8位MCU运行Linux、物联网传感器）仅需运行1-2个进程，可裁剪CFS之外的调度类（如RT、DL），降低内核体积。

```c


// 1. 修改调度类链表（kernel/sched/sched.h），仅保留CFS
static const struct sched_class *const sched_classes[] = {
    &idle_sched_class,   // 空闲调度类（必需）
    &fair_sched_class,   // CFS调度类（保留）
    // &rt_sched_class,    // 实时调度类（裁剪）
    // &dl_sched_class,    // 截止时间调度类（裁剪）
    NULL,
};

// 2. 内核配置关闭RT/DL支持（.config）
# CONFIG_RT_GROUP_SCHED is not set
# CONFIG_DEADLINE_GROUP_SCHED is not set

// 3. 裁剪相关源码文件（Makefile）
obj-$(CONFIG_FAIR_GROUP_SCHED) += fair.o
# obj-$(CONFIG_RT_GROUP_SCHED) += rt.o
# obj-$(CONFIG_DEADLINE_GROUP_SCHED) += dl.o

```

效果：内核体积从1.5MB降至800KB，内存占用从2MB降至512KB，满足传感器节点需求。

3.3 异构核调度适配：big.LITTLE任务分配优化

通过修改CFS的任务核选择逻辑，让高算力任务自动运行在大核，低功耗任务运行在小核，结合EAS实现“性能-功耗”平衡。

```c


// 修改kernel/sched/fair.c的select_task_rq_fair函数
static int select_task_rq_fair(struct task_struct *p, int prev_cpu, int sd_flag, int wake_flags)
{
    int target_cpu = prev_cpu;
    struct cpumask *big_core_mask = cpumask_of(4-7);
    struct cpumask *little_core_mask = cpumask_of(0-3);

    // 1. 高算力任务（如AI推理，通过进程名识别）分配到大核
    if (strstr(p->comm, "ai_infer") || strstr(p->comm, "video_decode")) {
        target_cpu = cpumask_first_and(big_core_mask, cpu_online_mask);
    }
    // 2. 低功耗任务（如日志、传感器采集）分配到小核
    else if (strstr(p->comm, "log") || strstr(p->comm, "sensor")) {
        target_cpu = cpumask_first_and(little_core_mask, cpu_online_mask);
    }
    // 3. 其他任务由EAS调度
    else {
        target_cpu = select_task_rq_eas(p, prev_cpu, sd_flag, wake_flags);
    }

    return target_cpu;
}

```

实验1：模拟小对象高频分配，观测Slab缓存增长
（1）实验代码（用户态应用，模拟10000个小对象分配）
```c
// slab_demo.c
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>

#define OBJECT_COUNT 10000  // 分配10000个对象
#define OBJECT_SIZE  256    // 每个对象256字节（Slab管理范围）

int main() {
    void *objects[OBJECT_COUNT];
    int i;

    // 第一步：分配10000个小对象
    printf("Allocating %d objects (each %d bytes)...\n", OBJECT_COUNT, OBJECT_SIZE);
    for (i = 0; i < OBJECT_COUNT; i++) {
        objects[i] = malloc(OBJECT_SIZE);  // malloc底层调用kmalloc（Slab）
        if (!objects[i]) {
            perror("malloc failed");
            return -1;
        }
    }
    printf("Allocation done. Press Enter to free...\n");
    getchar();  // 暂停，方便观测

    // 第二步：释放所有对象
    printf("Freeing all objects...\n");
    for (i = 0; i < OBJECT_COUNT; i++) {
        free(objects[i]);  // free底层调用kmem_cache_free
    }
    printf("Free done. Press Enter to exit...\n");
    getchar();

    return 0;
}
```

（2）交叉编译与运行
