2.3 ION跨进程共享实操（用户态示例）
ION的核心价值在于跨进程共享，以下通过"进程A分配内存-进程B共享访问"的示例，展示完整使用流程（基于ARM64架构，需链接libion库）
2.3.1 进程A：分配内存并生成共享fd
```c

#include <stdio.h>
#include <stdlib.h>
#include <fcntl.h>
#include <ion/ion.h>
#include <sys/mman.h>

#define BUF_SIZE (1024 * 1024)  // 1MB共享内存

int main() {
    int ion_fd, buf_fd;
    ion_user_handle_t handle;
    void *buf_addr;

    // 1. 打开ION设备
    ion_fd = open("/dev/ion", O_RDWR);
    if (ion_fd < 0) {
        perror("open /dev/ion failed");
        return -1;
    }

    // 2. 分配CMA类型的内存（堆ID需根据实际系统调整）
    int ret = ion_alloc(ion_fd, BUF_SIZE, 0, ION_HEAP_TYPE_CMA, 0, &handle);
    if (ret < 0) {
        perror("ion_alloc failed");
        close(ion_fd);
        return -1;
    }

    // 3. 将内存句柄转换为文件描述符（用于共享和映射）
    ret = ion_share(ion_fd, handle, &buf_fd);
    if (ret < 0) {
        perror("ion_share failed");
        ion_free(ion_fd, handle);
        close(ion_fd);
        return -1;
    }

    // 4. 映射内存到用户态并写入数据
    buf_addr = mmap(NULL, BUF_SIZE, PROT_READ | PROT_WRITE, MAP_SHARED, buf_fd, 0);
    if (buf_addr == MAP_FAILED) {
        perror("mmap failed");
        close(buf_fd);
        ion_free(ion_fd, handle);
        close(ion_fd);
        return -1;
    }
    sprintf(buf_addr, "ION Shared Memory Test");
    printf("Process A: Write data to shared memory: %s\n", (char*)buf_addr);

    // 5. 传递buf_fd给进程B（实际通过Binder/管道等IPC机制）
    printf("Process A: Shared fd = %d, pass to Process B\n", buf_fd);
    getchar();  // 等待进程B访问完成

    // 6. 释放资源
    munmap(buf_addr, BUF_SIZE);
    close(buf_fd);
    ion_free(ion_fd, handle);
    close(ion_fd);
    return 0;
}
```

2.3.2 进程B：导入fd并访问共享内存
```c

#include <stdio.h>
#include <fcntl.h>
#include <ion/ion.h>
#include <sys/mman.h>

#define BUF_SIZE (1024 * 1024)

int main(int argc, char *argv[]) {
    if (argc != 2) {
        printf("Usage: %s <shared_fd>\n", argv[0]);
        return -1;
    }

    int ion_fd, buf_fd = atoi(argv[1]);
    ion_user_handle_t handle;
    void *buf_addr;

    // 1. 打开ION设备
    ion_fd = open("/dev/ion", O_RDWR);
    if (ion_fd < 0) {
        perror("open /dev/ion failed");
        return -1;
    }

    // 2. 从接收的fd导入内存句柄
    int ret = ion_import(ion_fd, buf_fd, &handle);
    if (ret < 0) {
        perror("ion_import failed");
        close(ion_fd);
        return -1;
    }

    // 3. 映射内存到用户态并读取数据
    buf_addr = mmap(NULL, BUF_SIZE, PROT_READ | PROT_WRITE, MAP_SHARED, buf_fd, 0);
    if (buf_addr == MAP_FAILED) {
        perror("mmap failed");
        ion_free(ion_fd, handle);
        close(ion_fd);
        return -1;
    }
    printf("Process B: Read data from shared memory: %s\n", (char*)buf_addr);

    // 4. 释放资源
    munmap(buf_addr, BUF_SIZE);
    ion_free(ion_fd, handle);
    close(ion_fd);
    return 0;
}
```

2.3.3 编译与运行验证
```bash

# 编译（需链接libion库）
arm-linux-gnueabihf-gcc process_a.c -o process_a -lion
arm-linux-gnueabihf-gcc process_b.c -o process_b -lion

# 运行进程A（获取共享fd）
root@rk3568:~# ./process_a
Process A: Write data to shared memory: ION Shared Memory Test
Process A: Shared fd = 3, pass to Process B

# 另开终端运行进程B（传入fd）
root@rk3568:~# ./process_b 3
Process B: Read data from shared memory: ION Shared Memory Test
```

3.3 编程级脏页控制：sync_file_range使用

嵌入式开发中，对于高可靠性场景（如视频录制、日志存储），仅通过内核参数调优无法满足精细化的脏页控制需求，需通过`sync_file_range`系统调用手动控制脏页回写时机，避免数据丢失。

该API支持“同步指定文件的指定范围脏页”，比`sync`（同步所有文件）更高效。

3.3.1 API原型与参数说明
```c

#include <fcntl.h>

// 功能：同步文件的指定范围脏页
// 参数：
//   fd：文件描述符（需可写权限）
//   offset：起始偏移量（字节）
//   nbytes：同步范围大小（字节，0表示从offset到文件末尾）
//   flags：同步模式（核心参数）
// 返回值：0成功，-1失败（errno指示错误）
int sync_file_range(int fd, off64_t offset, off64_t nbytes, unsigned int flags);
```

核心`flags`参数取值：

- `SYNC_FILE_RANGE_WAIT_BEFORE`：等待之前提交的回写操作完成，再执行后续操作；

- `SYNC_FILE_RANGE_WRITE`：将指定范围的脏页提交给`flusher`线程，触发回写（非阻塞）；

- `SYNC_FILE_RANGE_WAIT_AFTER`：等待本次提交的回写操作完成（阻塞）。

3.3.2 嵌入式场景示例：视频录制脏页控制

视频录制场景中，需周期性回写帧数据脏页，避免突发断电丢失过多数据，同时避免频繁回写影响录制性能。示例代码如下：

```c

#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>
#include <errno.h>

#define VIDEO_FRAME_SIZE (1024 * 1024)  // 单帧大小1MB
#define TOTAL_FRAMES 100                // 总帧数100（100MB）
#define SYNC_INTERVAL 10                // 每录制10帧同步一次脏页

int main() {
    int fd;
    char *frame_buf;
    int i, ret;

    // 1. 分配帧缓冲区（模拟视频帧数据）
    frame_buf = malloc(VIDEO_FRAME_SIZE);
    if (!frame_buf) {
        perror("malloc frame buf failed");
        return -1;
    }
    memset(frame_buf, 0x12, VIDEO_FRAME_SIZE);

    // 2. 打开视频文件（O_DIRECT避免页缓存，此处为演示脏页控制关闭该选项）
    fd = open("/mnt/video_recording.h264", O_WRONLY | O_CREAT | O_TRUNC, 0644);
    if (fd < 0) {
        perror("open video file failed");
        free(frame_buf);
        return -1;
    }

    // 3. 模拟视频录制：写入帧数据，周期性同步脏页
    for (i = 0; i < TOTAL_FRAMES; i++) {
        // 写入单帧数据（产生脏页）
        ret = write(fd, frame_buf, VIDEO_FRAME_SIZE);
        if (ret != VIDEO_FRAME_SIZE) {
            perror("write frame failed");
            break;
        }
        printf("Recorded frame %d/%d\n", i+1, TOTAL_FRAMES);

        // 每录制10帧，同步一次脏页（提交回写并等待完成）
        if ((i+1) % SYNC_INTERVAL == 0) {
            off64_t offset = i * VIDEO_FRAME_SIZE;
            // 同步从offset开始的10帧数据（10MB）
            ret = sync_file_range(fd, offset, SYNC_INTERVAL * VIDEO_FRAME_SIZE,
                                 SYNC_FILE_RANGE_WRITE | SYNC_FILE_RANGE_WAIT_AFTER);
            if (ret < 0) {
                perror("sync_file_range failed");
                break;
            }
            printf("Synced dirty pages for frames %d~%d\n", i-9, i+1);
        }

        usleep(100000);  // 模拟录制间隔（100ms/帧）
    }

    // 4. 录制完成，同步所有剩余脏页
    ret = sync_file_range(fd, 0, 0, SYNC_FILE_RANGE_WRITE | SYNC_FILE_RANGE_WAIT_AFTER);
    if (ret < 0) {
        perror("final sync failed");
    } else {
        printf("Recording completed, all dirty pages synced\n");
    }

    // 5. 释放资源
    close(fd);
    free(frame_buf);
    return 0;
}
```

代码说明：
每录制10帧（10MB）调用`sync_file_range`同步对应范围的脏页，确保即使突发断电，最多丢失10帧数据；录制完成后同步所有脏页，保障数据完整性。
相比`sync`函数，该方式仅同步视频文件的指定范围，不影响系统其他脏页，性能更优。

col10.value:
结合上述需求，采用“CMA预留物理连续内存+ION管理缓冲区并实现跨层共享”的方案，

整体流程为：系统启动时通过设备树预留CMA区域→ION初始化CMA堆→驱动层通过ION分配缓冲区并绑定DMA→应用层通过ION共享缓冲区获取帧数据。

以下为具体实现步骤（基于Linux 5.10内核）：
2.1 第一步：CMA区域设备树（DTS）配置

通过设备树预留专门给摄像头的CMA区域，指定物理地址、大小及缓存属性，确保内存独立且满足DMA需求。

以RK3568的设备树为例，修改`arch/arm64/boot/dts/rockchip/rk3568.dtsi`：
```dts

/* 1. 预留CMA区域：放在reserved-memory节点下 */
reserved-memory {
    #address-cells = <2>;
    #size-cells = <2>;
    ranges;

    /* 摄像头专用CMA区域：基地址0x7f000000，大小16MB（预留比计算值多4MB冗余） */
    camera_cma: camera@7f000000 {
        compatible = "shared-dma-pool";  // 标识为DMA共享内存池
        reg = <0x0 0x7f000000 0x0 0x01000000>;  // 基地址(高32位,低32位) 大小(高32位,低32位)
        reusable;  // 支持内核复用（未被摄像头使用时可作为普通内存）
        memory-region = <&camera_cma_attr>;  // 关联缓存属性
        status = "okay";
    };
};

/* 2. 配置内存属性：指定Cache策略为Write-through（适配DMA） */
memory-attributes {
    camera_cma_attr: camera-attr {
        compatible = "linux,memory-attributes";
        linux,memory-attr = <0x2>;  // AttrIndx=2，对应RK3568的Write-through策略
    };
};

/* 3. 摄像头设备节点绑定CMA区域 */
&i2c2 {  // OV5640连接在I2C2总线上
    ov5640: camera@3c {
        compatible = "ovti,ov5640";
        reg = <0x3c>;
        /* 其他配置：时钟、引脚等省略 */
        memory-region = <&camera_cma>;  // 绑定预留的CMA区域
        status = "okay";
    };
};
```

关键配置说明：
① `reg`字段需结合芯片 datasheet 确认，确保地址范围未被其他设备占用；
② 大小预留16MB（比计算的12MB多4MB），避免内存碎片导致分配失败；
③ `Write-through`策略确保DMA写入的数据直接同步到内存，CPU读取时无需额外刷新Cache。

col11.value:
2.3.1 驱动层实现（摄像头驱动关键代码）

驱动初始化时从ION的CMA堆分配缓冲区，注册DMA回调函数，当摄像头采集完成后通过DMA写入缓冲区：

```c

#include <linux/ion.h>
#include <linux/dma-mapping.h>
#include <linux/video_device.h>

// 全局变量：ION相关句柄与缓冲区信息
struct ion_client *camera_ion_client;
ion_user_handle_t camera_ion_handle[3];  // 3个缓冲帧的句柄
dma_addr_t dma_addr[3];  // DMA地址（物理地址）
void *virt_addr[3];       // 虚拟地址（驱动层访问用）
#define BUF_SIZE 4194304  // 单帧大小4MB（1080P YUV422）

// 1. ION初始化：获取CMA堆并创建客户端
static int camera_ion_init(struct device *dev) {
    struct ion_heap_data heap_data;
    int heap_id = -1;

    // 1.1 获取ION设备文件描述符
    int ion_fd = open("/dev/ion", O_RDWR);
    if (ion_fd < 0) {
        dev_err(dev, "open /dev/ion failed\n");
        return -ENODEV;
    }

    // 1.2 创建ION客户端
    camera_ion_client = ion_client_create(ion_fd);
    if (!camera_ion_client) {
        dev_err(dev, "ion client create failed\n");
        close(ion_fd);
        return -ENOMEM;
    }

    // 1.3 查找CMA堆ID（通过堆名匹配摄像头专用CMA区域）
    struct ion_heap_query query = {0};
    query.cnt = 1;
    query.heaps = &heap_data;
    if (ion_query_heaps(ion_fd, &query) < 0) {
        dev_err(dev, "ion query heaps failed\n");
        return -EIO;
    }
    for (int i = 0; i < query.cnt; i++) {
        if (strcmp(heap_data.name, "camera@7f000000") == 0) {  // 匹配设备树中CMA区域名
            heap_id = heap_data.heap_id;
            break;
        }
    }
    if (heap_id < 0) {
        dev_err(dev, "find CMA heap failed\n");
        return -ENODEV;
    }

    // 1.4 分配3个连续内存缓冲区（CMA堆）
    for (int i = 0; i < 3; i++) {
        int ret = ion_alloc(camera_ion_client, BUF_SIZE, 0, 
                           (1 << heap_id), 0, &camera_ion_handle[i]);
        if (ret < 0) {
            dev_err(dev, "ion alloc buf %d failed\n", i);
            return ret;
        }
        // 映射为虚拟地址（驱动层访问）
        virt_addr[i] = ion_map_kernel(camera_ion_client, camera_ion_handle[i], 
                                      0, BUF_SIZE, PROT_READ | PROT_WRITE);
        // 转换为DMA地址（供摄像头DMA传输）
        dma_addr[i] = ion_phys(camera_ion_client, camera_ion_handle[i]);
        dev_info(dev, "buf %d: virt=0x%p, dma=0x%lx\n", i, virt_addr[i], dma_addr[i]);
    }
    return 0;
}

// 2. DMA回调函数：摄像头采集完成后触发，标记缓冲区为可读
static void camera_dma_done(int buf_idx) {
    // 通知应用层缓冲区可读（通过V4L2事件或信号量，此处省略）
    dev_info(&ov5640_dev, "frame %d captured, dma addr=0x%lx\n", buf_idx, dma_addr[buf_idx]);
}

// 3. 驱动probe函数（初始化入口）
static int ov5640_probe(struct i2c_client *client, const struct i2c_device_id *id) {
    struct device *dev = &client->dev;
    int ret;

    // 初始化ION缓冲区
    ret = camera_ion_init(dev);
    if (ret < 0) {
        return ret;
    }

    // 初始化DMA：绑定缓冲区地址，注册完成回调（不同芯片DMA驱动不同，此处简化）
    ret = camera_dma_init(dev, dma_addr, 3, camera_dma_done);
    if (ret < 0) {
        return ret;
    }

    // 启动摄像头采集（省略V4L2相关配置）
    ov5640_start_capture();
    return 0;
}
```

2.3.2 应用层实现（帧数据读取）

应用层通过ION的fd传递机制共享驱动层分配的缓冲区，读取帧数据并进行后续处理（如显示、压缩）。

需链接`libion`库（嵌入式系统需交叉编译）：
```c

#include <stdio.h>
#include <ion/ion.h>
#include <sys/mman.h>
#include <fcntl.h>

#define BUF_COUNT 3
#define BUF_SIZE 4194304

int main() {
    int ion_fd, camera_fd;
    ion_user_handle_t handles[BUF_COUNT];
    void *bufs[BUF_COUNT];
    int fds[BUF_COUNT];

    // 1. 打开ION设备和摄像头设备
    ion_fd = open("/dev/ion", O_RDWR);
    camera_fd = open("/dev/video0", O_RDWR);  // 摄像头设备节点（V4L2标准）
    if (ion_fd < 0 || camera_fd < 0) {
        perror("open device failed");
        return -1;
    }

    // 2. 从摄像头驱动获取ION缓冲区的fd（通过V4L2 IOCTL命令，简化为函数调用）
    get_camera_ion_fds(camera_fd, fds, BUF_COUNT);  // 实际为IOCTL(VIDIOC_G_EXT_CTRLS)

    // 3. 将fd导入为ION句柄，并映射为用户态虚拟地址
    for (int i = 0; i < BUF_COUNT; i++) {
        ion_import(ion_fd, fds[i], &handles[i]);
        bufs[i] = mmap(NULL, BUF_SIZE, PROT_READ | PROT_WRITE, 
                       MAP_SHARED, fds[i], 0);
        if (bufs[i] == MAP_FAILED) {
            perror("mmap failed");
            return -1;
        }
    }

    // 4. 循环读取帧数据（等待驱动通知，此处用轮询简化）
    while (1) {
        int ready_idx = wait_camera_buf_ready(camera_fd);  // 等待缓冲区就绪
        if (ready_idx < 0) break;

        // 读取帧数据（示例：打印前10字节YUV数据）
        printf("frame %d: ", ready_idx);
        for (int i = 0; i < 10; i++) {
            printf("%02x ", ((unsigned char*)bufs[ready_idx])[i]);
        }
        printf("\n");

        // 通知驱动缓冲区已处理，可重新用于采集
        release_camera_buf(camera_fd, ready_idx);
    }

    // 5. 释放资源
    for (int i = 0; i < BUF_COUNT; i++) {
        munmap(bufs[i], BUF_SIZE);
        ion_free(ion_fd, handles[i]);
        close(fds[i]);
    }
    close(ion_fd);
    close(camera_fd);
    return 0;
}
```

