camera_cma: camera@7f000000 {
    compatible = "shared-dma-pool";
    reg = <0x0 0x7f000000 0x0 0x01000000>;
    reusable;
    memory-region = <&camera_cma_attr>;
    heap-name = "camera@7f000000";  // 显式指定堆名
