3.2.2 eBPF程序开发（捕获内存分配）

编写eBPF程序`mem_trace.bpf.c`，挂载到malloc（用户态）和kmalloc（内核态）函数，采集进程ID、分配大小、调用栈：

```c

#include <vmlinux.h>
#include <bpf/bpf_helpers.h>
#include <bpf/bpf_tracing.h>
#include <bpf/bpf_core_read.h>

// 定义输出数据结构（进程ID、分配大小、调用栈ID）
struct mem_event {
    u32 pid;
    u64 size;
    u32 stack_id;
};

// eBPF映射：存储调用栈（stack_id→调用栈）
struct {
    __uint(type, BPF_MAP_TYPE_STACK_TRACE);
    __uint(key_size, sizeof(u32));
    __uint(value_size, sizeof(u64) * 16);  // 调用栈深度16
    __uint(max_entries, 1024);
} stack_map SEC(".maps");

// eBPF映射：输出事件到用户态
struct {
    __uint(type, BPF_MAP_TYPE_PERF_EVENT_ARRAY);
    __uint(key_size, sizeof(int));
    __uint(value_size, sizeof(int));
} perf_map SEC(".maps");

// 追踪用户态malloc函数
SEC("uprobe//lib/x86_64-linux-gnu/libc.so.6:malloc")
int BPF_UPROBE(malloc_trace, u64 size) {
    struct mem_event e = {};
    e.pid = bpf_get_current_pid_tgid() >> 32;  // 获取进程ID
    e.size = size;
    // 获取调用栈ID
    e.stack_id = bpf_get_stackid(ctx, &stack_map, BPF_F_USER_STACK);
    // 发送事件到用户态
    bpf_perf_event_output(ctx, &perf_map, BPF_F_CURRENT_CPU, &e, sizeof(e));
    return 0;
}

// 追踪内核态kmalloc函数
SEC("kprobe/kmalloc")
int BPF_KPROBE(kmalloc_trace, u64 size, gfp_t gfp_flags) {
    struct mem_event e = {};
    e.pid = bpf_get_current_pid_tgid() >> 32;
    e.size = size;
    // 获取内核调用栈ID
    e.stack_id = bpf_get_stackid(ctx, &stack_map, 0);
    bpf_perf_event_output(ctx, &perf_map, BPF_F_CURRENT_CPU, &e, sizeof(e));
    return 0;
}

char _license[] SEC("license") = "GPL";  // eBPF程序需GPL许可
```

