    ```c
    #include <linux/debugfs.h>
    #include <linux/fs.h>

    // 调试目录和节点指针
    static struct dentry *debug_dir;
    static struct dentry *reg_val_node;

    // 读取调试节点的回调函数（用户执行cat时调用）
    static ssize_t reg_val_read(struct file *file, char __user *buf, size_t len, loff_t *pos) {
        u8 reg_val = 0;
        char temp_buf[32];
        // 读取传感器寄存器值（硬件相关操作）
        reg_val = i2c_smbus_read_byte_data(sensor_client, 0x01);
        // 格式化数据
        snprintf(temp_buf, sizeof(temp_buf), "sensor_reg_0x01: 0x%x\n", reg_val);
        // 拷贝数据到用户态
        return simple_read_from_buffer(buf, len, pos, temp_buf, strlen(temp_buf));
    }

    // 调试节点的文件操作集
    static const struct file_operations reg_val_fops = {
        .owner = THIS_MODULE,
        .read = reg_val_read,
        .open = simple_open,
    };

    // 驱动初始化时创建调试节点
    static int __init temp_sensor_init(void) {
        // 创建调试目录temp_sensor
        debug_dir = debugfs_create_dir("temp_sensor", NULL);
        if (!debug_dir) return -ENOMEM;
        // 在目录下创建调试节点reg_val
        reg_val_node = debugfs_create_file("reg_val", 0444, debug_dir, NULL, &reg_val_fops);
        if (!reg_val_node) {
            debugfs_remove(debug_dir);
            return -ENOMEM;
        }
        return 0;
    }

    // 驱动卸载时删除调试节点
    static void __exit temp_sensor_exit(void) {
        debugfs_remove(reg_val_node);
        debugfs_remove(debug_dir);
    }
    module_init(temp_sensor_init);
    module_exit(temp_sensor_exit);
