进阶操作（E级）：驱动中注册sysfs属性
嵌入式驱动开发中，自定义sysfs属性是调试/控制硬件的核心手段，以下为温度传感器驱动中注册“温度读取”属性的核心代码框架：  
```c
#include <linux/kobject.h>
#include <linux/sysfs.h>
#include <linux/device.h>

// 设备私有数据（存储温度值）
struct temp_sensor_dev {
    struct device *dev;
    int temp;  // 温度值（单位：℃）
};
static struct temp_sensor_dev *ts_dev;

// sysfs属性读取回调（内核→用户态）
static ssize_t temp_show(struct device *dev, struct device_attribute *attr, char *buf)
{
    // 模拟读取硬件温度（嵌入式实际场景需替换为寄存器读取）
    ts_dev->temp = 28;  // 示例：当前温度28℃
    return sprintf(buf, "%d\n", ts_dev->temp);
}

// 定义sysfs属性（只读属性，name=temp，show回调=temp_show）
static DEVICE_ATTR_RO(temp);

// 驱动probe函数中注册sysfs属性
static int temp_sensor_probe(struct platform_device *pdev)
{
    int ret;
    ts_dev = devm_kzalloc(&pdev->dev, sizeof(*ts_dev), GFP_KERNEL);
    ts_dev->dev = &pdev->dev;

    // 注册temp属性到/sys/devices/.../（设备对应的sysfs目录）
    ret = device_create_file(ts_dev->dev, &dev_attr_temp);
    if (ret) {
        dev_err(ts_dev->dev, "sysfs属性注册失败\n");
        return ret;
    }
    dev_info(ts_dev->dev, "温度传感器sysfs属性注册成功\n");
    return 0;
}

// 驱动remove函数中注销sysfs属性
static int temp_sensor_remove(struct platform_device *pdev)
{
    device_remove_file(ts_dev->dev, &dev_attr_temp);
    return 0;
}

// 平台驱动结构体（嵌入式常用驱动框架）
static struct platform_driver temp_sensor_driver = {
    .probe = temp_sensor_probe,
    .remove = temp_sensor_remove,
    .driver = {
        .name = "temp-sensor",
        .owner = THIS_MODULE,
    },
};
module_platform_driver(temp_sensor_driver);

MODULE_LICENSE("GPL");
MODULE_DESCRIPTION("嵌入式温度传感器sysfs属性示例");
