3.2 读写节点回调（如采样率、温度阈值）
读写节点需同时实现`read`（返回当前值）和`write`（接收用户态输入并修改参数）回调：
```c
// 回调函数：读取采样率（debug_sampling_rate节点）
static ssize_t sampling_rate_read(struct file *file, char __user *buf, size_t len, loff_t *pos)
{
    char temp_buf[64];
    int ret;

    ret = snprintf(temp_buf, sizeof(temp_buf), "sampling_rate(Hz): %u\n", sensor_sampling_rate);
    if (ret < 0)
        return ret;

    return simple_read_from_buffer(buf, len, pos, temp_buf, strlen(temp_buf));
}

// 回调函数：修改采样率（debug_sampling_rate节点）
static ssize_t sampling_rate_write(struct file *file, const char __user *buf, size_t len, loff_t *pos)
{
    char temp_buf[32];
    uint32_t new_rate;
    int ret;

    // 从用户态拷贝输入数据（用户态echo的字符串）
    if (len > sizeof(temp_buf) - 1)
        return -EINVAL;  // 输入过长，返回无效参数

    ret = copy_from_user(temp_buf, buf, len);
    if (ret)
        return -EFAULT;  // 拷贝失败

    temp_buf[len] = '\0';  // 手动添加字符串结束符

    // 将字符串转为整数（采样率支持1/10/50Hz）
    ret = kstrtouint(temp_buf, 10, &new_rate);
    if (ret)
        return ret;

    // 校验采样率合法性（嵌入式场景需限制参数范围，避免硬件异常）
    if (new_rate != 1 && new_rate != 10 && new_rate != 50) {
        dev_warn(&g_sensor_client->dev, "invalid sampling rate: %u, support 1/10/50Hz\n", new_rate);
        return -EINVAL;
    }

    // 更新采样率，并配置传感器硬件（实际场景需通过I2C写入寄存器）
    sensor_sampling_rate = new_rate;
    config_sensor_sampling_rate(new_rate);  // 自定义函数：配置传感器硬件

    dev_info(&g_sensor_client->dev, "sampling rate updated to %u Hz\n", new_rate);
    return len;  // 返回成功写入的字节数
}

// 回调函数：读取温度阈值（debug_temp_threshold节点）
static ssize_t temp_threshold_read(struct file *file, char __user *buf, size_t len, loff_t *pos)
{
    char temp_buf[64];
    int ret;

    ret = snprintf(temp_buf, sizeof(temp_buf), "temp_threshold(℃): %d\n", sensor_temp_threshold);
    if (ret < 0)
        return ret;

    return simple_read_from_buffer(buf, len, pos, temp_buf, strlen(temp_buf));
}

// 回调函数：修改温度阈值（debug_temp_threshold节点）
static ssize_t temp_threshold_write(struct file *file, const char __user *buf, size_t len, loff_t *pos)
{
    char temp_buf[32];
    int32_t new_thresh;
    int ret;

    // 拷贝用户态输入
    if (len > sizeof(temp_buf) - 1)
        return -EINVAL;

    ret = copy_from_user(temp_buf, buf, len);
    if (ret)
        return -EFAULT;

    temp_buf[len] = '\0';

    // 字符串转整数（阈值范围：-40℃~85℃，传感器硬件支持范围）
    ret = kstrtos32(temp_buf, 10, &new_thresh);
    if (ret)
        return ret;

    if (new_thresh < -40 || new_thresh > 85) {
        dev_warn(&g_sensor_client->dev, "invalid threshold: %d℃, range -40~85℃\n", new_thresh);
        return -EINVAL;
    }

    // 更新阈值并配置硬件
    sensor_temp_threshold = new_thresh;
    config_sensor_threshold(new_thresh);  // 自定义函数：写入传感器阈值寄存器

    dev_info(&g_sensor_client->dev, "temp threshold updated to %d℃\n", new_thresh);
    return len;
}

// 读写节点的文件操作集（实现read、write、open）
static const struct file_operations rw_fops = {
    .owner = THIS_MODULE,
    .open = simple_open,
    .read = NULL,  // 后续为不同节点赋值不同read回调
    .write = NULL, // 后续为不同节点赋值不同write回调
};
```

3.3 注册所有调试节点
在`probe`函数中，基于上述回调函数注册4个调试节点，设置节点权限（只读节点设为0444，读写节点设为0666）：
```c
// 在temp_sensor_probe函数中添加节点注册代码
static int temp_sensor_probe(struct i2c_client *client, const struct i2c_device_id *id)
{
    // （前面代码：保存I2C客户端、创建debugfs目录）

    // 步骤2：注册采样率节点（读写，权限0666）
    rw_fops.read = sampling_rate_read;
    rw_fops.write = sampling_rate_write;
    debug_sampling_rate = debugfs_create_file(
        "sampling_rate",        // 节点名称
        0666,                   // 权限：用户/组/其他均可读写
        debug_root_dir,         // 父目录：temp_sensor
        NULL,                   // 私有数据：无
        &rw_fops                // 文件操作集
    );
    if (!debug_sampling_rate) {
        dev_err(&client->dev, "create sampling_rate node failed!\n");
        goto err_remove_dir;  // 创建失败，回滚目录
    }

    // 步骤3：注册温度阈值节点（读写，权限0666）
    rw_fops.read = temp_threshold_read;
    rw_fops.write = temp_threshold_write;
    debug_temp_threshold = debugfs_create_file(
        "temp_threshold",
        0666,
        debug_root_dir,
        NULL,
        &rw_fops
    );
    if (!debug_temp_threshold) {
        dev_err(&client->dev, "create temp_threshold node failed!\n");
        goto err_remove_sampling_rate;
    }

    // 步骤4：注册中断次数节点（只读，权限0444）
    ro_fops.read = irq_count_read;
    debug_irq_count = debugfs_create_file(
        "irq_count",
        0444,  // 权限：仅可读
        debug_root_dir,
        NULL,
        &ro_fops
    );
    if (!debug_irq_count) {
        dev_err(&client->dev, "create irq_count node failed!\n");
        goto err_remove_temp_threshold;
    }

    // 步骤5：注册原始温度节点（只读，权限0444）
    ro_fops.read = raw_temp_read;
    debug_raw_temp = debugfs_create_file(
        "raw_temp",
        0444,
        debug_root_dir,
        NULL,
        &ro_fops
    );
    if (!debug_raw_temp) {
        dev_err(&client->dev, "create raw_temp node failed!\n");
        goto err_remove_irq_count;
    }

    dev_info(&client->dev, "all debugfs nodes created successfully\n");
    return 0;

    // 错误回滚：节点创建失败时，依次删除已创建的节点和目录
err_remove_irq_count:
    debugfs_remove(debug_irq_count);
err_remove_temp_threshold:
    debugfs_remove(debug_temp_threshold);
err_remove_sampling_rate:
    debugfs_remove(debug_sampling_rate);
err_remove_dir:
    debugfs_remove(debug_root_dir);
    return -ENOMEM;
}
```

