1.1 头文件引入与全局变量定义
```c
#include <linux/module.h>
#include <linux/platform_device.h>
#include <linux/gpio.h>
#include <linux/pwm.h>
#include <linux/sysfs.h>
#include <linux/kobject.h>
#include <linux/device.h>
#include <linux/uaccess.h>

// LED硬件配置（需根据实际设备修改）
#define LED_GPIO_PIN    12          // LED控制GPIO引脚
#define PWM_CHIP        "pwmchip0"  // PWM芯片名称
#define PWM_CHANNEL     0           // PWM通道号
#define PWM_PERIOD_NS   20000       // PWM周期（20us，对应50kHz）

// LED核心数据结构（包含硬件句柄和属性值）
struct led_dev {
    struct device *dev;             // 设备指针（关联Linux设备模型）
    struct pwm_device *pwm;         // PWM设备句柄
    uint8_t brightness;             // 当前亮度（0~255）
    struct kobject *led_kobj;       // sysfs属性关联的kobject
};

static struct led_dev g_led_dev;    // 全局LED设备实例
```

1.2 sysfs属性读写回调实现
sysfs属性通过`show`（读属性时调用）和`store`（写属性时调用）回调与驱动交互，
需遵循“字符串格式交互”
（用户态读写的是文本，驱动需完成“字符串→数值”“数值→字符串”转换）。

```c
// 回调函数：读取亮度（cat brightness时触发）
static ssize_t brightness_show(struct device *dev, struct device_attribute *attr, char *buf)
{
    struct led_dev *led = &g_led_dev;
    // 将亮度数值转为字符串（格式："128\n"，便于用户态读取）
    return snprintf(buf, PAGE_SIZE, "%u\n", led->brightness);
}

// 回调函数：设置亮度（echo 数值 > brightness时触发）
static ssize_t brightness_store(struct device *dev, struct device_attribute *attr, const char *buf, size_t count)
{
    struct led_dev *led = &g_led_dev;
    uint8_t new_brightness;
    int ret;

    // 1. 将用户态输入的字符串转为整数（限制范围0~255）
    ret = kstrtou8(buf, 10, &new_brightness);
    if (ret) {
        dev_err(dev, "invalid brightness value: %s\n", buf);
        return -EINVAL;
    }

    // 2. 校验亮度范围（避免超出硬件支持）
    if (new_brightness > 255) {
        dev_warn(dev, "brightness out of range (0~255), set to 255\n");
        new_brightness = 255;
    }

    // 3. 更新PWM占空比（亮度=0→占空比0%，亮度=255→占空比100%）
    uint32_t duty_ns = (uint64_t)new_brightness * PWM_PERIOD_NS / 255;
    ret = pwm_set_duty_cycle(led->pwm, duty_ns);
    if (ret) {
        dev_err(dev, "failed to set pwm duty cycle: %d\n", ret);
        return ret;
    }

    // 4. 启动PWM（若亮度为0，可关闭PWM节能）
    if (new_brightness > 0) {
        ret = pwm_enable(led->pwm);
        if (ret) {
            dev_err(dev, "failed to enable pwm: %d\n", ret);
            return ret;
        }
    } else {
        pwm_disable(led->pwm);
    }

    // 5. 更新驱动内部亮度变量
    led->brightness = new_brightness;
    dev_info(dev, "brightness updated to %u (duty: %u ns)\n", new_brightness, duty_ns);

    return count;  // 返回成功写入的字节数
}

// 定义sysfs属性：名称=brightness，权限=0666（读写），绑定show/store回调
static DEVICE_ATTR_RW(brightness);  // 定义了 dev_attr_brightness

// 属性组：将多个属性归类（此处仅brightness，便于扩展其他属性如"enable"）
static struct attribute *led_attrs[] = {
    &dev_attr_brightness.attr,
    NULL  // 结束标记
};
ATTRIBUTE_GROUPS(led);  // 生成属性组描述符：led_groups  // 定义了 led_groups
```

1.3 设备初始化与sysfs属性注册
通过platform驱动框架初始化设备，关联sysfs属性组，完成硬件（GPIO、PWM）初始化：

```c
// platform驱动probe函数（设备匹配成功后执行）
static int led_drv_probe(struct platform_device *pdev)
{
    struct led_dev *led = &g_led_dev;
    int ret;

    led->dev = &pdev->dev;
    dev_set_drvdata(&pdev->dev, led);  // 绑定设备与驱动数据

    // 1. 申请GPIO（若需通过GPIO控制LED使能，可选）
    ret = devm_gpio_request(led->dev, LED_GPIO_PIN, "led_en");
    if (ret) {
        dev_err(led->dev, "failed to request gpio %d: %d\n", LED_GPIO_PIN, ret);
        return ret;
    }
    gpio_direction_output(LED_GPIO_PIN, 1);  // GPIO设为输出，高电平使能LED

    // 2. 申请并初始化PWM设备
    led->pwm = devm_pwm_get_from_of_node(led->dev, pdev->dev.of_node, NULL, PWM_CHIP, PWM_CHANNEL);
    if (IS_ERR(led->pwm)) {
        ret = PTR_ERR(led->pwm);
        dev_err(led->dev, "failed to get pwm: %d\n", ret);
        return ret;
    }

    // 3. 配置PWM周期
    ret = pwm_set_period(led->pwm, PWM_PERIOD_NS);
    if (ret) {
        dev_err(led->dev, "failed to set pwm period: %d\n", ret);
        return ret;
    }

    // 4. 注册sysfs属性组（核心步骤：将属性暴露到/sys/devices/.../led/）
    ret = device_add_groups(led->dev, led_groups);
    if (ret) {
        dev_err(led->dev, "failed to add sysfs attributes: %d\n", ret);
        return ret;
    }

    // 5. 初始化默认亮度（50%亮度=128）
    led->brightness = 128;
    brightness_store(led->dev, &dev_attr_brightness, "128", 3);

    dev_info(led->dev, "led driver probe success, sysfs attribute created\n");
    return 0;
}

// platform驱动remove函数（卸载驱动时执行）
static int led_drv_remove(struct platform_device *pdev)
{
    struct led_dev *led = dev_get_drvdata(&pdev->dev);

    // 1. 移除sysfs属性组
    device_remove_groups(&pdev->dev, led_groups);

    // 2. 关闭PWM，释放资源（devres机制自动释放GPIO、PWM）
    pwm_disable(led->pwm);
    gpio_set_value(LED_GPIO_PIN, 0);

    dev_info(led->dev, "led driver removed\n");
    return 0;
}

// 设备树匹配表（用于DTB匹配设备，嵌入式主流方式）
static const struct of_device_id led_drv_of_match[] = {
    { .compatible = "custom,led-drv" },
    {}  // 结束标记
};
MODULE_DEVICE_TABLE(of, led_drv_of_match);

// platform驱动结构体
static struct platform_driver led_platform_driver = {
    .probe = led_drv_probe,
    .remove = led_drv_remove,
    .driver = {
        .name = "custom-led-driver",
        .of_match_table = led_drv_of_match,
    },
};

module_platform_driver(led_platform_driver);

MODULE_LICENSE("GPL");
MODULE_DESCRIPTION("LED Brightness Control Driver via Sysfs");
MODULE_AUTHOR("Embedded Linux Developer");
```

