#include <linux/workqueue.h>

// 温度传感器硬件配置（根据实际传感器修改）
#define SENSOR_I2C_ADDR 0x48        // I2C设备地址
#define SENSOR_TEMP_REG 0x00        // 温度寄存器地址
#define SENSOR_UPDATE_INTERVAL 1000 // 数据更新周期（1000ms=1Hz）

// 传感器核心数据结构
struct temp_sensor_dev {
    struct i2c_client *client;      // I2C客户端指针
    struct device *dev;             // 设备指针
    struct delayed_work update_work;// 延迟工作队列（周期性采样）
    float temp;                     // 实时温度（单位：℃）
};

static struct temp_sensor_dev g_sensor_dev;
```

1.2 sysfs只读属性回调实现
只读属性仅需实现`show`回调，返回驱动缓存的温度数据（避免用户态每次读取都触发硬件I2C操作，提升效率）：
```c
// 回调函数：读取温度（cat temp时触发）
static ssize_t temp_show(struct device *dev, struct device_attribute *attr, char *buf)
{
    struct temp_sensor_dev *sensor = &g_sensor_dev;
    // 格式化温度数据（保留1位小数，如"25.6\n"）
    return snprintf(buf, PAGE_SIZE, "%.1f\n", sensor->temp);
}

// 定义sysfs只读属性：名称=temp，权限=0444
static DEVICE_ATTR_RO(temp);

// 属性组（可扩展其他属性如"sensor_id"、"sample_rate"）
static struct attribute *sensor_attrs[] = {
    &dev_attr_temp.attr,
    NULL
};
ATTRIBUTE_GROUPS(sensor);
```

1.3 周期性数据采样（工作队列实现）
通过延迟工作队列（delayed_work）实现周期性采样，避免阻塞sysfs回调（用户态读取时直接返回缓存数据）：
```c
// 工作队列回调：周期性读取传感器数据
static void temp_sensor_update_work(struct work_struct *work)
{
    struct temp_sensor_dev *sensor = container_of(work, struct temp_sensor_dev, update_work.work);
    int16_t raw_temp;
    int ret;

    // 1. 通过I2C读取传感器原始数据（16位整数，单位：0.01℃）
    raw_temp = i2c_smbus_read_word_data(sensor->client, SENSOR_TEMP_REG);
    if (raw_temp < 0) {
        dev_err(sensor->dev, "failed to read sensor data: %d\n", raw_temp);
        goto reschedule;
    }

    // 2. 原始数据转换为温度（根据传感器datasheet调整，此处以TI TMP102为例）
    sensor->temp = raw_temp / 256.0f;  // TMP102：16位数据，高8位为整数，低4位为小数

    dev_dbg(sensor->dev, "sensor temp updated: %.1f℃\n", sensor->temp);

reschedule:
    // 3. 重新调度工作队列（周期性执行）
    schedule_delayed_work(&sensor->update_work, msecs_to_jiffies(SENSOR_UPDATE_INTERVAL));
}
```

1.4 驱动初始化与属性注册
```c
// I2C驱动probe函数（I2C设备匹配成功后执行）
static int temp_sensor_probe(struct i2c_client *client, const struct i2c_device_id *id)
{
    struct temp_sensor_dev *sensor = &g_sensor_dev;
    int ret;

    sensor->client = client;
    sensor->dev = &client->dev;
    dev_set_drvdata(&client->dev, sensor);

    // 1. 初始化延迟工作队列（首次执行延迟100ms）
    INIT_DELAYED_WORK(&sensor->update_work, temp_sensor_update_work);
    schedule_delayed_work(&sensor->update_work, msecs_to_jiffies(100));

    // 2. 注册sysfs属性组（暴露temp属性）
    ret = device_add_groups(sensor->dev, sensor_groups);
    if (ret) {
        dev_err(sensor->dev, "failed to add sysfs attributes: %d\n", ret);
        cancel_delayed_work_sync(&sensor->update_work);
        return ret;
    }

    // 3. 初始化温度（默认0℃）
    sensor->temp = 0.0f;

    dev_info(sensor->dev, "temp sensor driver probe success, sysfs attribute created\n");
    return 0;
}

// I2C驱动remove函数
static int temp_sensor_remove(struct i2c_client *client)
{
    struct temp_sensor_dev *sensor = dev_get_drvdata(&client->dev);

    // 1. 移除sysfs属性组
    device_remove_groups(&client->dev, sensor_groups);

    // 2. 取消工作队列，停止采样
    cancel_delayed_work_sync(&sensor->update_work);

    dev_info(sensor->dev, "temp sensor driver removed\n");
    return 0;
}

// I2C设备ID表
static const struct i2c_device_id temp_sensor_id[] = {
    {"custom-temp-sensor", 0},
    {}
};
MODULE_DEVICE_TABLE(i2c, temp_sensor_id);

// 设备树匹配表
static const struct of_device_id temp_sensor_of_match[] = {
    { .compatible = "custom,temp-sensor" },
    {}
};
MODULE_DEVICE_TABLE(of, temp_sensor_of_match);

// I2C驱动结构体
static struct i2c_driver temp_sensor_i2c_driver = {
    .probe = temp_sensor_probe,
    .remove = temp_sensor_remove,
    .id_table = temp_sensor_id,
    .driver = {
        .name = "custom-temp-sensor-drv",
        .of_match_table = temp_sensor_of_match,
    },
};

module_i2c_driver(temp_sensor_i2c_driver);

MODULE_LICENSE("GPL");
MODULE_DESCRIPTION("Temp Sensor Data Read Driver via Sysfs");
MODULE_AUTHOR("Embedded Linux Developer");
```

1.5 设备树配置（I2C传感器节点）
```dts
// 设备树片段（添加到I2C控制器节点下，如i2c1）
temp-sensor@48 {
    compatible = "custom,temp-sensor";  // 与驱动of_match_table一致
    reg = <0x48>;                       // I2C设备地址
    status = "okay";
};
```

