```dts
// 注释：设备树支持单行注释（//）和多行注释（/* ... */）
/dts-v1/;  // 声明设备树版本（固定为v1）
/plugin/;  // 声明为可加载片段（简化示例，实际量产可省略）

// 根节点：所有设备的顶级节点
/ {
    // 核心属性：描述当前系统（开发板）的兼容性，供内核匹配
    compatible = "test,led-dev-board"; // compatible 属性错误：内核无法识别开发板类型，可能无法启动或加载错误的板级支持包
    model = "Test LED Development Board";  // 开发板型号（可选，用于标识）
                                           // 仅影响 cat /proc/device-tree/model 的信息显示
    // CPU节点：描述ARM CPU核心（此处以双核心为例，简化配置）
    cpus {
        #address-cells = <1>;  // 地址单元格数量（CPU编号为1个32位整数）
        #size-cells = <0>;     // 大小单元格数量（CPU无“大小”属性，为0）

        // CPU核心0节点（编号为0）
        cpu@0 {
            compatible = "arm,cortex-a7";  // CPU架构（Cortex-A7为例）
            device_type = "cpu";
            reg = <0>;  // CPU编号
        };

        // CPU核心1节点（编号为1）
        cpu@1 {
            compatible = "arm,cortex-a7";
            device_type = "cpu";
            reg = <1>;
        };
    };

    // GPIO控制器节点：LED依赖的GPIO控制器（需与硬件实际GPIO控制器匹配）
    gpio1: gpio@0x01C20800 {  // 标签：gpio1；节点名：gpio@基地址（实际基地址需查芯片手册）
        compatible = "allwinner,sunxi-gpio";  // GPIO控制器兼容驱动名（芯片厂商定义）
        reg = <0x01C20800 0x400>;  // 寄存器基地址+地址长度（查芯片手册获取）
        #gpio-cells = <2>;  // GPIO属性单元格数量（<2>; 引脚号 + 标志位）
                            // ← 声明：用我，得给2个参数
        status = "okay";  // 设备状态：okay（启用）、disabled（禁用）
    };

    // 外设节点：LED灯节点（挂载在根节点下，依赖gpio1控制器）
    leds {
        compatible = "gpio-leds";  // 兼容“GPIO类LED”通用驱动（内核自带）
        label = "system-leds";     // 节点标识（可选）

        // 具体LED子节点（led0）
        led0: led@0 {
            label = "user-led";  // LED标识（应用层可通过此名访问）
            // GPIO属性：引用gpio1控制器的第3个引脚，输出方向，低电平激活
            gpios = <&gpio1 3 1>;  // 引脚号 | 激活电平(0=low,1=high) 
            default-state = "off";  // 默认状态：熄灭
            linux,default-trigger = "none";  // 触发方式：无（手动控制）
        };
    };
};
```

节点是设备树的核心组成部分，用于描述一个硬件设备，
语法格式为：`标签: 节点名@地址 { 子节点; 属性; };`

- 节点名：格式为  设备类型@地址
“地址”是设备在父总线中的地址（如GPIO控制器的寄存器基地址），
无地址时可省略“@地址”（如LED节点`led@0`）；

- 层级关系：节点通过嵌套实现层级，
如LED节点`led0`是`leds`节点的子节点，`leds`是根节点的子节点，
对应硬件的“根→LED组→单个LED”层级；

/dts-v1/;
/plugin/;

/ {
    // 根节点（无标签，无@地址）
    compatible = "fsl,imx6ull-evk";

    // 层级1：SOC节点（有基地址）
    soc: soc@02000000 {
        compatible = "simple-bus";
        reg = <0x02000000 0x100000>;
        #address-cells = <1>;
        #size-cells = <1>;

        // 层级2：GPIO控制器（有寄存器基地址）
        gpio5: gpio@020ac000 {
            compatible = "fsl,imx6ul-gpio";
            reg = <0x020ac000 0x4000>;
            #gpio-cells = <2>;
        };
    };

    // 层级1：LED父节点（无寄存器地址，省略@）
    leds {
        compatible = "gpio-leds";

        // 层级2：LED子节点（@后为单元编号，非寄存器地址）
        led0: led@0 {
            label = "red";
            gpios = <&gpio5 2 GPIO_ACTIVE_LOW>;
        };

        led1: led@1 {
            label = "green";
            gpios = <&gpio5 3 GPIO_ACTIVE_LOW>;
        };
    };
};

属性用于描述节点的具体参数，格式为：`属性名 = <值>;
`（数值类型）或`属性名 = "值";`（字符串类型），核心规则如下：

（1）常见核心属性
|属性名        |作用                               |示例
|compatible    |驱动匹配标识，“厂商名,设备名”格式|`compatible = "gpio-leds";`
|reg           |设备地址信息，“基地址 长度”格式  |`reg = <0x01C20800 0x400>;`
|#address-cells|子节点地址的单元格数量             |`#address-cells = <1>;`
|#size-cells   |子节点地址长度的单元格数量         |`#size-cells = <0>;`
|status        |设备状态（okay/disabled）          |`status = "okay";`

（2）数据类型
属性值支持多种数据类型，开发中常用的有4种：
- 字符串类型：用于描述名称、兼容性等，用双引号包裹，如`label = "user-led";`；
- 32位整数类型：用尖括号`<>`包裹，单个整数或多个整数（单元格），如`#gpio-cells = <3>;`；
- 数组类型：多个整数的集合，如`reg = <0x01C20800 0x400>;`（基地址+长度数组）；
- 引用类型：通过标签引用其他节点，如`gpios = <&gpio1 3 1>`中的`&gpio1`。 

    soc: soc@f7000000 {
        compatible = "simple-bus";

        /* reg数组：基地址(64位) + 长度(32位) */
        reg = <0x0 0xf7000000 0x0 0x1000000>;  

        /* #cells数组：子节点地址/长度单元格数 */
        #address-cells = <2>;
        #size-cells = <1>;

        /* GPIO控制器节点 */
        gpio0: gpio@ffd04000 {
            /* 字符串：驱动匹配标识 */
            compatible = "intel,socfpga-agilex-gpio";

            /* 数组：寄存器范围（64位基地址 + 32位长度） */
            reg = <0x0 0xffd04000 0x0 0x1000>;

            /* 32位整数：GPIO参数单元格数 */
            #gpio-cells = <2>;  // 引脚号 + 标志位

            /* 字符串：设备状态枚举值 */
            status = "okay";  // 或 "disabled"
        };
    };

- 标签：为节点起的别名，

格式为“标签名:*”，紧跟节点名前（如`gpio1: gpio@0x01C20800`），
作用是简化节点引用，避免写长节点路径；

- 引用：通过“`&标签名`”引用节点，
如引用gpio1控制器节点时，直接用`&gpio1`，无需写完整路径`&/gpio@0x01C20800`；

- 注意：标签名在整个DTS中必须唯一，否则编译时会报错“duplicate label”。

    /* ========= 定义带标签的节点 ========= */

    /* 标签：main_i2c0 - I2C控制器 */
    main_i2c0: i2c@ffd02000 {
        compatible = "intel,socfpga-agilex-i2c";
        reg = <0x0 0xffd02000 0x0 0x100>;
        #address-cells = <1>;
        #size-cells = <0>;
        status = "okay";
    };

    /* ========= 通过&标签引用节点 ========= */

    /* EEPROM节点：引用main_i2c0标签 */
    eeprom@50 {
        compatible = "atmel,24c02";
        reg = <0x50>;
        /* 引用I2C总线，无需写完整路径 */
        i2c-parent = <&main_i2c0>;  
    };

1. 步骤1：of_core初始化：
内核启动时，在`start_kernel`（内核初始化入口）中调用`of_init`函数，完成of_core模块的初始化，
包括初始化全局根节点指针`dt_root`、注册设备树调试接口（如debugfs中的dt目录）。

2. 步骤2：DTB解析与节点树构建：
由`of_parse_dt_parsing`函数完成，核心是遍历DTB的二进制数据，按照设备树语法规则解析出每个节点和属性，创建对应的`device_node`和`property`结构体，
并通过链表组织成树形结构，最终将根节点地址赋值给`dt_root`。
例如解析test_led.dts中的`leds`节点时，会创建一个`device_node`结构体，其`name`字段为“leds”，`parent`字段指向根节点。
    leds {
        compatible = "gpio-leds";

        led0: led@0 {
            label = "status-led";
            gpios = <&gpio0 15 1>;
        };
    };
// led@0节点
led0_node {
    .name = "led",               // 节点名（@前的部分）
    .full_name = "led@0",        // 完整名（含@地址）
    .parent = &leds_node,        // 父节点是leds
    .child = NULL,               // 无子节点
    .sibling = NULL,             // 无兄弟节点
    .properties = {              // 属性链表
        { .name = "label", .value = "status-led", ... },
        { .name = "gpios", .value = <phandle 15 1>, ... },
        NULL
    }
};
3. 步骤3：总线设备生成：
由`of_platform_populate`函数触发，该函数递归遍历设备树的节点树，对每个节点执行“匹配总线类型→生成对应设备结构体”的操作。
例如：  根节点下的`leds`节点无明确总线属性，默认生成`platform_device`；

4. I2C控制器节点下的`sht30@44`节点（温湿度传感器），会生成`i2c_client`结构体。

5. 步骤4：设备注册到总线：
生成设备结构体后，调用对应总线的注册函数（如`platform_device_register`）将设备注册到总线的设备链表中，等待驱动匹配。
此时通过`ls /sys/devices/platform/`命令可看到生成的`leds`设备目录，证明解析成功。

`compatible`属性（兼容属性）是设备树节点与驱动绑定的核心依据，
其格式为“厂商名,设备名”的字符串列表（支持多个值，用于兼容不同驱动），
例如test_led.dts中`leds`节点的定义：
```dts

leds {
    compatible = "gpio-leds", "test,user-led";  // 支持两个兼容值
    /* 其他属性... */
};
```

驱动程序中需定义“匹配表”（`of_match_table`），存储驱动支持的`compatible`值，示例如下（LED驱动的匹配表）：
```c

#include <linux/of.h>
#include <linux/platform_device.h>

// 驱动支持的compatible值列表
static const struct of_device_id led_of_match[] = {
    { .compatible = "gpio-leds" },  // 与设备树第一个值匹配
    { .compatible = "test,user-led" },  // 与设备树第二个值匹配
    { /* Sentinel */ }  // 哨兵值，标识列表结束
};
MODULE_DEVICE_TABLE(of, led_of_match);  // 将匹配表注册到内核
```

匹配规则为“按顺序比对，找到第一个匹配项即停止”，具体逻辑：
1. 内核遍历设备结构体的`dev.of_node`指针（指向对应设备树节点），读取`compatible`属性的字符串列表；
2. 遍历驱动的`of_match_table`列表，将每个列表项的`compatible`值与设备节点的列表逐一比对；
3. 若找到完全一致的字符串，匹配成功；若遍历结束仍无匹配项，匹配失败，驱动无法绑定设备。

platform总线是嵌入式Linux的“通用总线”，用于连接无明确硬件总线（如I2C、SPI）的外设（如LED、按键），
其匹配流程是设备树与驱动绑定的典型场景，完整流程分为“设备注册”和“驱动注册”两个阶段，
核心依赖`platform_match`函数（匹配逻辑入口）。

（1）设备注册阶段：从节点到platform_device

该阶段在设备树解析的步骤3和4完成，`of_platform_populate`函数递归遍历节点树时，对每个无明确总线属性的节点执行：
```c

// 简化后的核心逻辑
static int of_platform_device_create(struct device_node *np, const char *bus_id,
                                     struct device *parent)
{
    struct platform_device *pdev;
    // 1. 分配platform_device结构体
    pdev = platform_device_alloc("", -1);
    if (!pdev) return -ENOMEM;
    // 2. 关联设备树节点（关键：将node指针存入dev.of_node）
    pdev->dev.of_node = of_node_get(np);
    // 3. 注册到platform总线
    return platform_device_add(pdev);
}
```

注册完成后，设备结构体`platform_device`被添加到platform总线的设备链表中，
其`dev.of_node`字段指向对应的设备树节点，为后续匹配提供依据。

（2）驱动注册阶段：匹配与probe函数执行

驱动通过`platform_driver_register`函数注册时，内核会触发总线的匹配逻辑，
调用`platform_match`函数比对设备与驱动，源码逻辑如下（简化版）：
```c

static int platform_match(struct device *dev, struct device_driver *drv)
{
    struct platform_device *pdev = to_platform_device(dev);
    struct platform_driver *pdrv = to_platform_driver(drv);

    // 关键：设备树匹配逻辑（优先执行）
    if (of_driver_match_device(dev, drv))
        return 1;  // 匹配成功

    // 其他匹配方式（如设备名匹配，兼容旧驱动）
    if (pdrv->id_table && platform_match_id(pdrv->id_table, pdev))
        return 1;
    return (strcmp(pdev->name, drv->name) == 0);
}
```

其中`of_driver_match_device`函数是设备树匹配的核心，
它会调用`of_match_device`函数比对设备节点的`compatible`属性与驱动的`of_match_table`，匹配成功后：
1. 内核将驱动与设备绑定，设置`dev.driver`指向驱动结构体；
2. 调用驱动的`probe`函数（驱动的初始化入口），在probe函数中可通过`dev.of_node`指针解析设备树属性，完成硬件初始化。

扩展：为何设备树匹配要优先于设备名匹配？
因为设备树匹配支持“一款驱动适配多款设备”（通过多个compatible值），而设备名匹配需一款设备对应一个驱动名，灵活性远低于设备树匹配，这也是设备树替代传统板级文件的核心优势之一。

#include <linux/gpio.h>
#include <linux/platform_device.h>

// 定义LED设备的私有数据结构（存储解析后的参数）
struct led_dev {
    int gpio_num;          // GPIO引脚号
    const char *label;     // LED标签
    int default_state;     // 默认状态（0：熄灭，1：点亮）
};
static const struct of_device_id led_of_match[] = {
    { .compatible = "gpio-leds", },  // 匹配设备树中的 compatible 属性
    { /* sentinel */ }  // 数组结尾标记
};
MODULE_DEVICE_TABLE(of, led_of_match);  // 声明为OF类型驱动

// 驱动probe函数（匹配成功后执行）
static int led_probe(struct platform_device *pdev)
{
    struct led_dev *led;
    struct device_node *led0_node;
    int ret;

    // 1. 分配私有数据结构体
    led = devm_kzalloc(&pdev->dev, sizeof(struct led_dev), GFP_KERNEL);
    if (!led) return -ENOMEM;

    // 2. 获取当前设备对应的设备树节点（从platform_device中获取）
    led0_node = pdev->dev.of_node;
    if (!led0_node) {
        dev_err(&pdev->dev, "device tree node not found\n");
        return -EINVAL;
    }

    // 3. 解析设备树属性，填充私有数据
    // 3.1 解析gpios属性，获取GPIO编号
    led->gpio_num = of_get_named_gpio(led0_node, "gpios", 0);
    if (led->gpio_num < 0) {
        dev_err(&pdev->dev, "failed to get gpio num\n");
        return led->gpio_num;
    }
    // 3.2 解析label属性（字符串）
    ret = of_property_read_string(led0_node, "label", &led->label);
    if (ret) {
        dev_warn(&pdev->dev, "label not found, use default\n");
        led->label = "default-led";
    }
    // 3.3 解析default-state属性，转换为数值
    const char *default_state_str;
    ret = of_property_read_string(led0_node, "default-state", &default_state_str);
    led->default_state = (ret == 0 && strcmp(default_state_str, "on") == 0) ? 1 : 0;

    // 4. 硬件初始化（使用解析后的参数）
    // 4.1 申请GPIO引脚
    ret = devm_gpio_request(&pdev->dev, led->gpio_num, led->label);
    if (ret) {
        dev_err(&pdev->dev, "failed to request gpio\n");
        return ret;
    }
    // 4.2 配置GPIO为输出模式，并设置默认状态
    gpio_direction_output(led->gpio_num, led->default_state);
    dev_info(&pdev->dev, "led probe success: gpio=%d, label=%s, default=%d\n",
             led->gpio_num, led->label, led->default_state);

    // 5. 保存私有数据到设备结构体
    platform_set_drvdata(pdev, led);
    return 0;
}

// 驱动结构体（关联probe函数和匹配表）
static struct platform_driver led_driver = {
    .probe = led_probe,
    .driver = {
        .name = "user-led-driver",
        .of_match_table = led_of_match,  // 关联设备树匹配表
    },
};
module_platform_driver(led_driver);  // 简化版注册宏
```

1. 完整DTS代码（基于sun8i-h3开发板）
在开发板专属DTS（如sun8i-h3-xxx-board.dts）的根节点下新增LED子节点，代码如下：
```dts

// 引用芯片核心DTSI文件（已包含GPIO控制器定义）
#include "sun8i-h3.dtsi"

/ {
    model = "XXX H3 Development Board";
    compatible = "xxx,h3-board", "allwinner,sun8i-h3";

    // 新增LED控制器节点（管理板上所有LED）
    leds {
        compatible = "gpio-leds";  // 匹配内核自带的gpio-leds驱动
        label = "board-leds";      // 节点标识，用于调试

        // 单个LED子节点（对应硬件连接的LED灯）
        user_led: led@0 {
            label = "user:red:led"; // LED标识，将显示在sysfs中
            /* 
             * gpio属性：引用gpio0控制器的PA10引脚，低电平有效
             * 格式：<&控制器标签 引脚号 激活电平>
             * 激活电平：0=高电平有效，1=低电平有效
             */
            gpios = <&gpio0 10 1>; 
            default-state = "off";  // 系统启动后默认状态：熄灭
            linux,default-trigger = "none";  // 无自动触发（手动控制）
        };
    };
};
```

1. 内核自带gpio-leds驱动的匹配逻辑
打开内核gpio-leds驱动源码，可找到核心匹配表定义，正是通过该表与设备树的`compatible`属性匹配：
```c
#include <linux/of.h>
#include <linux/platform_device.h>

// 驱动的设备树匹配表
static const struct of_device_id gpio_leds_of_match[] = {
    { .compatible = "gpio-leds" },  // 与设备树leds节点的compatible值完全匹配
    { /* Sentinel */ }
};
MODULE_DEVICE_TABLE(of, gpio_leds_of_match);  // 将匹配表注册到内核

// 驱动probe函数（匹配成功后执行）
static int gpio_led_probe(struct platform_device *pdev)
{
    struct device_node *np = pdev->dev.of_node;
    struct device_node *child;

    // 遍历leds节点的所有子节点（如user_led）
    for_each_child_of_node(np, child) {
        // 解析子节点的gpios、label等属性，初始化LED硬件
        gpio_led_create(child, &pdev->dev);
    }
    return 0;
}

// platform驱动结构体
static struct platform_driver gpio_led_driver = {
    .probe = gpio_led_probe,
    .driver = {
        .name = "gpio-leds",
        .of_match_table = gpio_leds_of_match,  // 关联匹配表
    },
};
```

匹配流程（复用3.4.4章节结论，不扩展原理）：
1. 内核解析LED设备树节点，生成`platform_device`结构体；
2. 遍历platform总线的驱动链表，找到`gpio-leds`驱动；
3. 比对设备节点的`compatible`属性与驱动的`of_match_table`，匹配成功后执行`probe`函数。

2. 自定义驱动的匹配示例（拓展学习）
若需自定义驱动（如添加LED闪烁逻辑），核心是编写匹配表关联设备树。
简化驱动代码如下（仅展示匹配核心部分）：
```c
#include <linux/leds.h>
#include <linux/of.h>

// 自定义驱动的匹配表（设备树节点compatible需改为"xxx,user-led"）
static const struct of_device_id my_led_of_match[] = {
    { .compatible = "xxx,user-led" },
    { /* Sentinel */ }
};
MODULE_DEVICE_TABLE(of, my_led_of_match);

// 自定义probe函数
static int my_led_probe(struct platform_device *pdev)
{
    struct device_node *np = pdev->dev.of_node;
    int gpio_num;

    // 解析设备树的gpios属性（核心：将设备树参数转为驱动变量）
    gpio_num = of_get_named_gpio(np, "gpios", 0);
    if (gpio_num < 0) {
        dev_err(&pdev->dev, "failed to get gpio\n");
        return -EINVAL;
    }

    // GPIO初始化（输出模式，默认熄灭）
    gpio_direction_output(gpio_num, 1);
    dev_info(&pdev->dev, "custom led driver probe success, gpio=%d\n", gpio_num);
    return 0;
}

static struct platform_driver my_led_driver = {
    .probe = my_led_probe,
    .driver = {
        .name = "my-user-led",
        .of_match_table = my_led_of_match,
    },
};
module_platform_driver(my_led_driver);
```

此时需将设备树LED节点的`compatible`属性改为`"xxx,user-led"`，确保驱动与设备树匹配。

