#include "sun8i-h3.dtsi"
#include "sun8i-h3-pinctrl.dtsi"

/ {
    // （可选）定义供电regulator节点，若直接使用3.3V可省略
    vcc_sensor: regulator@0 {
        compatible = "regulator-fixed";
        regulator-name = "vcc_sensor";
        regulator-min-microvolt = <3300000>;  // 3.3V
        regulator-max-microvolt = <3300000>;
        gpio = <&gpio0 13 0>;  // 用PA13控制供电开关
        enable-active-high;  // 高电平启用供电
    };
};

// 在I2C0控制器节点内新增SHT30子节点
&i2c0 {
    status = "okay";  // 确保I2C0启用
    clock-frequency = <400000>;  // 改为快速模式提升速率

    sht30@44 {  // 格式：设备名@I2C从机地址（0x44对应默认地址）
        compatible = "sensirion,sht30";  // 匹配SHT30驱动的compatible值
        reg = <0x44>;  // I2C从机地址，ADDR悬空时为0x44
        pinctrl-names = "default";
        pinctrl-0 = <&i2c0_pins>;  // 复用I2C0引脚配置
        vdd-supply = <&vcc_sensor>;  // 引用供电regulator（可选，直接供电可省略）
        /* 中断配置（可选，SHT30支持报警中断）
        interrupt-parent = <&gpio0>;
        interrupts = <14 IRQ_TYPE_EDGE_FALLING>;  // PA14作为中断引脚，下降沿触发
        */
    };
