```

2. 驱动与设备树匹配核心代码
SHT30驱动通过of_match_table与设备树compatible属性匹配，核心代码如下：

```c

#include <linux/i2c.h>
#include <linux/iio/iio.h>
#include <linux/of.h>

// 设备树匹配表（与DTS的compatible属性对应）
static const struct of_device_id sht3x_of_match[] = {
    { .compatible = "sensirion,sht30" },  // 匹配SHT30子节点
    { .compatible = "sensirion,sht31" },  // 兼容SHT31（同系列传感器）
    { /* Sentinel */ }
};
MODULE_DEVICE_TABLE(of, sht3x_of_match);

// IIO通道描述符：定义温度和湿度两个通道
static const struct iio_chan_spec sht3x_channels[] = {
    // 温度通道：类型为温度，数据16位，单位℃
    {
        .type = IIO_TEMP,
        .info_mask_separate = BIT(IIO_CHAN_INFO_RAW) | BIT(IIO_CHAN_INFO_SCALE),
        .info_mask_shared_by_type = BIT(IIO_CHAN_INFO_SAMP_FREQ),
        .datasheet_name = "Temperature",
    },
    // 湿度通道：类型为湿度，数据16位，单位%RH
    {
        .type = IIO_HUMIDITYRELATIVE,
        .info_mask_separate = BIT(IIO_CHAN_INFO_RAW) | BIT(IIO_CHAN_INFO_SCALE),
        .info_mask_shared_by_type = BIT(IIO_CHAN_INFO_SAMP_FREQ),
        .datasheet_name = "Humidity",
    },
};

// 私有数据结构体
struct sht3x_data {
    struct i2c_client *client;  // I2C客户端指针（通信核心）
    struct regulator *vdd;      // 供电regulator指针（可选）
    u32 addr;                   // 解析的I2C地址
};

// 驱动probe函数（匹配成功后执行，核心是解析属性+初始化IIO设备）
static int sht3x_probe(struct i2c_client *client, const struct i2c_device_id *id)
{
    struct sht3x_data *data;
    struct iio_dev *indio_dev;
    int ret;

    // 1. 分配IIO设备和私有数据结构体
    indio_dev = devm_iio_device_alloc(&client->dev, sizeof(struct sht3x_data));
    if (!indio_dev) return -ENOMEM;
    data = iio_priv(indio_dev);
    data->client = client;
    i2c_set_clientdata(client, indio_dev);

    // 2. 解析设备树属性（E级核心：从DTS获取配置参数）
    // 2.1 解析I2C地址（从client中获取，由DTS的reg属性设置）
    data->addr = client->addr;
    dev_info(&client->dev, "sht30 found at I2C address 0x%02x", data->addr);

    // 2.2 解析供电regulator（对应DTS的vdd-supply属性）
    data->vdd = devm_regulator_get_optional(&client->dev, "vdd");
    if (IS_ERR(data->vdd)) {
        ret = PTR_ERR(data->vdd);
        dev_err(&client->dev, "failed to get regulator: %d", ret);
        return ret;
    }
    // 启用供电（若有regulator）
    ret = regulator_enable(data->vdd);
    if (ret) {
        dev_err(&client->dev, "failed to enable regulator: %d", ret);
        return ret;
    }

    // 2.3 （可选）解析中断属性（对应DTS的interrupts属性）
    ret = devm_request_irq(&client->dev, client->irq, sht3x_irq_handler,
                          IRQF_TRIGGER_FALLING, "sht30-alert", data);
    if (ret) dev_warn(&client->dev, "failed to request interrupt: %d", ret);

    // 3. 初始化SHT30硬件（发送配置指令，如采样率）
    ret = sht3x_hw_init(data);
    if (ret) {
        regulator_disable(data->vdd);
        return ret;
    }

    // 4. 配置IIO设备并注册
    indio_dev->name = "sht3x";
    indio_dev->modes = INDIO_DIRECT_MODE;  // 直接采样模式
    indio_dev->channels = sht3x_channels;  // 关联通道描述符
    indio_dev->num_channels = ARRAY_SIZE(sht3x_channels);

    ret = devm_iio_device_register(&client->dev, indio_dev);
    if (ret) {
        dev_err(&client->dev, "failed to register IIO device: %d", ret);
        regulator_disable(data->vdd);
    }
    return ret;
}

// I2C驱动结构体（I2C设备的驱动核心，区别于platform驱动）
static struct i2c_driver sht3x_driver = {
    .probe = sht3x_probe,
    .id_table = sht3x_id_table,
    .driver = {
        .name = "sht3x",
        .of_match_table = sht3x_of_match,  // 关联设备树匹配表
    },
};
```

3. 数据读取与校准（工业级核心）
方式1：通过iio_sysfs读取原始数据（调试用）
IIO子系统会为每个传感器通道生成sysfs节点，直接通过cat命令读取原始数据和校准参数：
```bash

# 假设温度对应iio:device0，湿度对应iio:device1
# 1. 读取温度原始数据和缩放因子
cat /sys/bus/iio/devices/iio:device0/in_temp_raw
# 输出示例：25678（16位原始数据）
cat /sys/bus/iio/devices/iio:device0/in_temp_scale
# 输出示例：0.01（缩放因子，单位℃/LSB）
# 温度计算：原始数据 × 缩放因子 = 25678 × 0.01 = 25.678℃

# 2. 读取湿度原始数据和缩放因子
cat /sys/bus/iio/devices/iio:device1/in_humidityrelative_raw
# 输出示例：45321
cat /sys/bus/iio/devices/iio:device1/in_humidityrelative_scale
# 输出示例：0.0015258789（缩放因子，单位%RH/LSB）
# 湿度计算：45321 × 0.0015258789 ≈ 69.16%RH
```
方式2：通过应用程序读取校准后数据（工业应用用）
工业场景需编写应用程序调用IIO子系统接口，读取并校准数据（消除系统误差）。
以下是C语言示例程序，包含偏移校准功能：
```c

#include <stdio.h>
#include <stdlib.h>
#include <fcntl.h>
#include <unistd.h>
#include <string.h>

// 校准参数：偏移值（通过标准设备校准得到，假设温度偏移-0.5℃，湿度偏移+2%RH）
#define TEMP_OFFSET (-0.5)
#define HUMIDITY_OFFSET 2.0

// 读取IIO节点数据
float read_iio_data(const char *path) {
    char buf[32];
    int fd = open(path, O_RDONLY);
    if (fd < 0) { perror("open failed"); return -1; }
    read(fd, buf, sizeof(buf));
    close(fd);
    return atof(buf);
}

int main() {
    float temp_raw, temp_scale, temp;
    float humid_raw, humid_scale, humid;

    // 读取温度数据并校准
    temp_raw = read_iio_data("/sys/bus/iio/devices/iio:device0/in_temp_raw");
    temp_scale = read_iio_data("/sys/bus/iio/devices/iio:device0/in_temp_scale");
    temp = temp_raw * temp_scale + TEMP_OFFSET;

    // 读取湿度数据并校准
    humid_raw = read_iio_data("/sys/bus/iio/devices/iio:device1/in_humidityrelative_raw");
    humid_scale = read_iio_data("/sys/bus/iio/devices/iio:device1/in_humidityrelative_scale");
    humid = humid_raw * humid_scale + HUMIDITY_OFFSET;

    // 打印校准后数据（保留2位小数，工业显示标准）
    printf("Calibrated Temperature: %.2f℃\n", temp);
    printf("Calibrated Humidity: %.2f%%RH\n", humid);
    return 0;
}
```

编译与运行（交叉编译后复制到开发板）：
```bash

