// 1. 必选：指定编译兼容版本
/dts-v1/;
// 2. 必选：声明为Overlay（关键标识）
/plugin/;

// 3. 片段定义：每个扩展功能对应一个fragment（可多个）
fragment@0 {
    target = <&目标节点路径>;  // 指定要修改的主DTS节点（如UART1、GPIO控制器）
    __overlay__ {
        // 4. 叠加内容：要插入/修改的节点配置（与静态DTS语法一致）
        扩展节点定义;
    };
};

// （可选）多个片段：如同时配置UART和GPIO
fragment@1 {
    target = <&另一个目标节点>;
    __overlay__ {
        另一部分配置;
    };
};
```

易错点：`/plugin/`声明必须存在，否则编译后的Overlay无法被内核识别为“叠加层”，会被当作普通DTB处理导致加载失败。

2. EC20 4G模块Overlay完整代码（实战重点）
基于全志H3开发板，编写EC20模块的Overlay文件（ec20_4g_overlay.dts），
实现UART1启用、PA15/PA16引脚配置及EC20节点定义：
```dts

/dts-v1/;
/plugin/;

// 引入主DTS的引脚定义（仅用于引脚复用，无需引入完整主DTS）
#include <sun8i-h3-pinctrl.dtsi>

// 片段0：配置UART1（EC20通信接口）
fragment@0 {
    // 目标节点：主DTS中的UART1控制器节点（路径需与主DTS一致）
    target = <&uart1>;
    __overlay__ {
        status = "okay";  // 启用UART1（主DTS中默认可能为disabled）
        pinctrl-names = "default";
        // 引用主DTS中的UART1引脚复用节点（已在sun8i-h3-pinctrl.dtsi定义）
        pinctrl-0 = <&uart1_pins>;
        // UART核心参数（与EC20模块匹配）
        uart-has-rtscts = <0>;  // 禁用硬件流控
        current-speed = <115200>;  // 波特率115200
    };
};

// 片段1：配置GPIO（PA15=PWRKEY，PA16=NET灯）
fragment@1 {
    // 目标节点：主DTS中的GPIO0控制器节点（PA引脚属于GPIO0）
    target = <&gpio0>;
    __overlay__ {
        // 定义GPIO子节点（用于EC20控制）
        ec20_gpio: ec20-gpio {
            compatible = "gpio-leds";  // 复用gpio-leds驱动控制NET灯
            pinctrl-names = "default";
            // 自定义PA15和PA16的引脚复用配置
            pinctrl-0 = <&ec20_gpio_pins>;

            // PA16：NET灯（低电平点亮）
            ec20_net: net-led@0 {
                label = "ec20:net:led";
                gpios = <&gpio0 16 1>;  // GPIO0 PA16，低电平有效
                default-state = "off";
            };

            // PA15：PWRKEY（输出高电平触发模块上电）
            ec20_pwrkey: pwrkey@1 {
                label = "ec20:pwrkey:ctrl";
                gpios = <&gpio0 15 0>;  // GPIO0 PA15，高电平有效
                default-state = "low";
            };
        };
    };
};

// 片段2：定义EC20 4G模块总节点（关联UART和GPIO）
fragment@2 {
    // 目标节点：主DTS的根节点（将EC20节点添加到根节点下）
    target = <&root>;
    __overlay__ {
        ec20_4g: ec20@0 {
            compatible = "quectel,ec20";  // 匹配EC20的内核驱动
            status = "okay";
            // 关联UART1接口（与片段0的UART1节点绑定）
            uart = <&uart1>;
            // 关联GPIO控制节点（与片段1的ec20_gpio节点绑定）
            gpios = <&ec20_gpio 0 0>;  // 引用自定义GPIO子节点
            // 模块供电配置（若需软件控制供电，可关联regulator）
            vcc-supply = <&vcc3v3>;  // 引用主DTS中的3.3V电源节点
        };
    };
};

// 片段3：自定义PA15和PA16的引脚复用配置（补充主DTS未定义的配置）
fragment@3 {
    // 目标节点：主DTS的引脚控制器节点
    target = <&pinctrl>;
    __overlay__ {
        // 定义PA15和PA16的引脚功能
        ec20_gpio_pins: ec20-gpio-pins {
            pins = "PA15", "PA16";
            function = "gpio_inout";  // 设为通用GPIO模式
            drive-strength = <20>;  // 驱动能力20mA
            bias-pull-up = <1>;  // 上拉电阻使能
        };
    };
};
```

