2.  驱动与设备树匹配的核心：`of_match_table`
    驱动通过`of_match_table`结构体定义支持的`compatible`字符串，内核会自动匹配设备树中`compatible`属性与之相同的节点，匹配成功后才会执行`probe`函数。示例如下：
    ```c
    #include <linux/init.h>
    #include <linux/module.h>
    #include <linux/platform_device.h>
    #include <linux/of.h>  // 包含OF API头文件
    #include <linux/gpio.h>

    // 1. 定义驱动支持的compatible列表（与设备树对应）
    static const struct of_device_id led_of_match[] = {
        { .compatible = "vendor,led-dt" },  // 必须与设备树的compatible一致
        { /* Sentinel */ }  // 哨兵，标识列表结束（必须）
    };
    MODULE_DEVICE_TABLE(of, led_of_match);  // 向内核注册匹配表（必须）

    // 2. probe函数：匹配成功后执行，解析设备树并初始化硬件
    static int led_probe(struct platform_device *pdev)
    {
        struct device_node *led_node = pdev->dev.of_node;  // 匹配成功后，内核自动关联节点
        int led_gpio, ret;
        u32 reg_data[2];

        // 解析reg属性（基地址和长度）
        ret = of_property_read_u32_array(led_node, "reg", reg_data, 2);
        if (ret) {
            dev_err(&pdev->dev, "read reg failed: %d\n", ret);
            return ret;
        }
        dev_info(&pdev->dev, "reg: base=0x%x, size=0x%x\n", reg_data[0], reg_data[1]);

        // 解析led-gpio属性（GPIO引脚）
        led_gpio = of_get_named_gpio(led_node, "led-gpio", 0);
        if (!gpio_is_valid(led_gpio)) {
            dev_err(&pdev->dev, "invalid gpio: %d\n", led_gpio);
            return -EINVAL;
        }
        dev_info(&pdev->dev, "led gpio: %d\n", led_gpio);

        // 初始化GPIO（申请并配置为输出）
        ret = devm_gpio_request(&pdev->dev, led_gpio, "led-dt");
        if (ret) return ret;
        gpio_direction_output(led_gpio, 1);  // 点亮LED

        dev_info(&pdev->dev, "led probe success\n");
        return 0;
    }

    // 3. 平台驱动结构体（关联probe函数）
    static struct platform_driver led_platform_driver = {
        .probe = led_probe,
        .driver = {
            .name = "led-dt-driver",
            .of_match_table = led_of_match,  // 关联匹配表（核心）
            .owner = THIS_MODULE,
        },
    };

    module_platform_driver(led_platform_driver);
    MODULE_LICENSE("GPL");
    ```
    关键逻辑：
    - `of_match_table`是驱动与设备树匹配的“桥梁”，内核启动时会遍历设备树节点，对比`compatible`字段；
    - 匹配成功后，内核会将设备树节点指针（`of_node`）赋值给`platform_device->dev.of_node`，驱动在`probe`中可直接使用，无需手动查找节点。

