2.  驱动源码编写（led_char_drv.c）
    ```c
    #include <linux/init.h>
    #include <linux/module.h>
    #include <linux/fs.h>
    #include <linux/cdev.h>
    #include <linux/uaccess.h>
    #include <linux/gpio.h>
    #include <linux/device.h>

    #define LED_GPIO 12          // LED对应的GPIO引脚（全志H3的GPIO1_5）
    #define DEV_NAME "led_char"  // 设备名
    #define DEV_COUNT 1          // 设备数量

    // 全局变量
    static struct cdev led_cdev;
    static struct class *led_class;
    static dev_t led_dev_num;
    static int led_state = 0;     // LED状态（0：灭，1：亮）
    static char state_buf[16];    // 状态缓冲区（供read函数返回）

    // 1. 实现file_operations函数
    static int led_open(struct inode *inode, struct file *file)
    {
        int ret;
        // 申请GPIO（devm_前缀：设备销毁时自动释放）
        ret = devm_gpio_request(&file->f_dev, LED_GPIO, "led_char");
        if (ret < 0) {
            dev_err(&file->f_dev, "gpio request failed: %d\n", ret);
            return ret;
        }
        // 配置GPIO为输出模式，初始状态灭
        gpio_direction_output(LED_GPIO, 0);
        dev_info(&file->f_dev, "led device opened\n");
        return 0;
    }

    static ssize_t led_read(struct file *file, char __user *buf, size_t count, loff_t *loff)
    {
        int ret;
        // 拼接状态字符串（如"LED state: 1\n"）
        snprintf(state_buf, sizeof(state_buf), "LED state: %d\n", led_state);
        // 限制拷贝长度
        if (count > sizeof(state_buf)) {
            count = sizeof(state_buf);
        }
        // 内核→用户态拷贝状态
        ret = copy_to_user(buf, state_buf, count);
        if (ret > 0) {
            dev_err(&file->f_dev, "read failed: %d bytes\n", ret);
            return -EFAULT;
        }
        return count;
    }

    static ssize_t led_write(struct file *file, const char __user *buf, size_t count, loff_t *loff)
    {
        int ret;
        char cmd_buf[8];  // 存储用户态传入的命令（1或0）

        // 限制命令长度（仅需1字节：'0'或'1'）
        if (count > sizeof(cmd_buf) - 1) {
            count = sizeof(cmd_buf) - 1;
        }
        // 用户态→内核态拷贝命令
        ret = copy_from_user(cmd_buf, buf, count);
        if (ret > 0) {
            dev_err(&file->f_dev, "write failed: %d bytes\n", ret);
            return -EFAULT;
        }
        cmd_buf[count] = '\0';  // 手动加字符串结束符

        // 解析命令并控制LED
        if (cmd_buf[0] == '1') {
            gpio_set_value(LED_GPIO, 1);
            led_state = 1;
            dev_info(&file->f_dev, "LED turned on\n");
        } else if (cmd_buf[0] == '0') {
            gpio_set_value(LED_GPIO, 0);
            led_state = 0;
            dev_info(&file->f_dev, "LED turned off\n");
        } else {
            dev_err(&file->f_dev, "invalid cmd: %c（only 0/1）\n", cmd_buf[0]);
            return -EINVAL;
        }
        return count;
    }

    static int led_release(struct inode *inode, struct file *file)
    {
        dev_info(&file->f_dev, "led device closed\n");
        return 0;
    }

    // 2. 定义file_operations
    static const struct file_operations led_fops = {
        .owner = THIS_MODULE,
        .open = led_open,
        .read = led_read,
        .write = led_write,
        .release = led_release,
    };

    // 3. 模块加载函数
    static int __init led_char_init(void)
    {
        int ret;

        // 步骤1：动态申请设备号
        ret = alloc_chrdev_region(&led_dev_num, 0, DEV_COUNT, DEV_NAME);
        if (ret < 0) {
            dev_err(NULL, "alloc dev num failed: %d\n", ret);
            return ret;
        }
        dev_info(NULL, "alloc dev num: major=%d, minor=%d\n",
                 MAJOR(led_dev_num), MINOR(led_dev_num));

        // 步骤2：初始化cdev并注册
        cdev_init(&led_cdev, &led_fops);
        led_cdev.owner = THIS_MODULE;
        ret = cdev_add(&led_cdev, led_dev_num, DEV_COUNT);
        if (ret < 0) {
            dev_err(NULL, "add cdev failed: %d\n", ret);
            goto err_cdev;
        }

        // 步骤3：创建类和设备文件（自动创建/dev/led_char）
        led_class = class_create(THIS_MODULE, "led_class");
        if (IS_ERR(led_class)) {
            dev_err(NULL, "class create failed\n");
            ret = PTR_ERR(led_class);
            goto err_class;
        }
        device_create(led_class, NULL, led_dev_num, NULL, DEV_NAME);

        dev_info(NULL, "led char driver init success\n");
        return 0;

    // 错误处理（反向释放资源）
    err_class:
        cdev_del(&led_cdev);
    err_cdev:
        unregister_chrdev_region(led_dev_num, DEV_COUNT);
        return ret;
    }

    // 4. 模块卸载函数
    static void __exit led_char_exit(void)
    {
        device_destroy(led_class, led_dev_num);
        class_destroy(led_class);
        cdev_del(&led_cdev);
        unregister_chrdev_region(led_dev_num, DEV_COUNT);
        dev_info(NULL, "led char driver exit success\n");
    }

    module_init(led_char_init);
    module_exit(led_char_exit);
    MODULE_LICENSE("GPL");
    MODULE_DESCRIPTION("LED Character Device Driver");
    ```

2.  实战：带参数的LED驱动调试
    基于前文LED字符设备驱动，添加“闪烁频率”“调试开关”两个参数，实现“加载时指定频率，运行时开启调试日志”：
    ```c
    #include <linux/init.h>
    #include <linux/module.h>
    #include <linux/fs.h>
    #include <linux/gpio.h>
    #include <linux/timer.h>  // 定时器，用于LED闪烁

    #define LED_GPIO 12

    // 1. 定义模块参数（全局变量）
    static int blink_freq = 1;    // 闪烁频率（默认1Hz）
    static bool debug_en = false; // 调试开关（默认关闭）
    static char *dev_name = "led_param";  // 设备名（字符串参数）

    // 2. 声明模块参数（内核识别参数）
    module_param(blink_freq, int, 0644);    // 整数参数，权限0644
    module_param(debug_en, bool, 0644);     // 布尔参数
    module_param(dev_name, charp, 0644);    // 字符串参数

    // 3. 参数描述（可选，modinfo命令可查看）
    MODULE_PARM_DESC(blink_freq, "LED blink frequency (Hz), default 1");
    MODULE_PARM_DESC(debug_en, "Enable debug log (0: disable, 1: enable), default 0");
    MODULE_PARM_DESC(dev_name, "Device name, default 'led_param'");

    // 定时器回调函数（LED闪烁逻辑）
    static struct timer_list led_timer;
    static int led_state = 0;

    static void led_blink_func(struct timer_list *t)
    {
        led_state = !led_state;
        gpio_set_value(LED_GPIO, led_state);
        // 调试开关控制：仅开启时打印日志
        if (debug_en) {
            dev_info(NULL, "blink freq: %dHz, state: %d\n", blink_freq, led_state);
        }
        // 重新设置定时器（按blink_freq频率循环）
        mod_timer(t, jiffies + HZ / blink_freq);  // HZ是内核时钟频率（默认1000Hz）
    }

    // 模块加载函数
    static int __init led_param_init(void)
    {
        int ret;
        // 参数合法性检查（调试频率不能为0或负数）
        if (blink_freq <= 0) {
            dev_err(NULL, "invalid blink freq: %d（must >0）\n", blink_freq);
            return -EINVAL;
        }
        // 调试日志：仅开启时打印参数信息
        if (debug_en) {
            dev_info(NULL, "debug enable: blink_freq=%d, dev_name=%s\n",
                     blink_freq, dev_name);
        }
        // GPIO初始化
        ret = devm_gpio_request(NULL, LED_GPIO, dev_name);
        if (ret < 0) return ret;
        gpio_direction_output(LED_GPIO, 0);
        // 初始化定时器（启动闪烁）
        timer_setup(&led_timer, led_blink_func, 0);
        mod_timer(&led_timer, jiffies + HZ / blink_freq);
        dev_info(NULL, "led param driver init success\n");
        return 0;
    }

    // 模块卸载函数
    static void __exit led_param_exit(void)
    {
        del_timer(&led_timer);  // 删除定时器
        dev_info(NULL, "led param driver exit\n");
    }

    module_init(led_param_init);
    module_exit(led_param_exit);
    MODULE_LICENSE("GPL");
    ```

