2. 步骤1：编写LED设备树节点（基于全志H3开发板）
复用芯片级设备树（`sun8i-h3.dtsi`）中已定义的`pio`（GPIO控制器）节点，在根节点下添加LED设备节点：
```dts
/dts-v1/;
#include "sun8i-h3.dtsi"  // 引入芯片级设备树，包含pio节点定义

/ {
    model = "Allwinner H3 Demo Board";
    compatible = "allwinner,h3-demo", "allwinner,sun8i-h3";

    /* LED设备节点：挂在根节点下，命名遵循"设备类型@基地址" */
    led_platform: led@0 {
        compatible = "demo,led-platform";  // 匹配标识，需与驱动of_match_table一致
        status = "okay";                   // 启用节点，内核才会解析
        led-gpio = <&pio 1 5 GPIO_ACTIVE_LOW>;  // GPIO1组第5号引脚，低电平有效
        /* 注：GPIO_ACTIVE_LOW表示GPIO输出低电平时LED亮，与硬件连接方式匹配 */
    };
};
```
关键属性解析：
- `compatible = "demo,led-platform"`：驱动匹配的“身份证”，必须与驱动代码严格一致；
- `led-gpio = <&pio 1 5 GPIO_ACTIVE_LOW>`：自定义属性，指定LED连接的GPIO引脚（`&pio`引用GPIO控制器节点，1为组号，5为组内引脚号）。

3. 步骤2：编写最简Platform LED驱动代码（led_platform_drv.c）
驱动代码核心是实现`platform_driver`结构体，包含匹配表、`probe`（初始化）和`remove`（清理）函数：
```c
#include <linux/init.h>
#include <linux/module.h>
#include <linux/platform_device.h>
#include <linux/of.h>          // 设备树解析API
#include <linux/gpio.h>         // GPIO操作API
#include <linux/of_gpio.h>      // 设备树GPIO解析API

// 全局变量：存储LED的GPIO引脚号
static int led_gpio;

// 1. probe函数：设备与驱动匹配成功后自动调用，初始化硬件
static int led_platform_probe(struct platform_device *pdev)
{
    struct device_node *led_node = pdev->dev.of_node;  // 匹配成功的设备树节点
    int ret;

    /* 步骤1：从设备树解析LED的GPIO引脚号 */
    led_gpio = of_get_named_gpio_flags(led_node, "led-gpio", 0, NULL);
    if (!gpio_is_valid(led_gpio)) {  // 检查GPIO引脚号是否有效
        dev_err(&pdev->dev, "invalid led gpio: %d\n", led_gpio);
        return -EINVAL;
    }

    /* 步骤2：申请GPIO引脚（避免与其他设备冲突） */
    ret = devm_gpio_request(&pdev->dev, led_gpio, "led-platform");
    if (ret) {
        dev_err(&pdev->dev, "gpio request failed: %d\n", ret);
        return ret;
    }

    /* 步骤3：配置GPIO为输出模式，初始状态熄灭（高电平，因引脚低电平有效） */
    gpio_direction_output(led_gpio, 1);
    dev_info(&pdev->dev, "probe success: led gpio=%d\n", led_gpio);

    // 点亮LED（输出低电平）
    gpio_set_value(led_gpio, 0);
    dev_info(&pdev->dev, "led turned on\n");
    return 0;
}

// 2. remove函数：驱动卸载或设备移除时调用，清理资源
static int led_platform_remove(struct platform_device *pdev)
{
    // 熄灭LED
    gpio_set_value(led_gpio, 1);
    dev_info(&pdev->dev, "led turned off, remove success\n");
    // 无需手动释放GPIO：devm_前缀的函数会自动释放资源
    return 0;
}

// 3. 设备树匹配表：驱动支持的compatible列表
static const struct of_device_id led_of_match[] = {
    { .compatible = "demo,led-platform" },  // 与设备树节点的compatible一致
    { /* Sentinel */ }  // 哨兵，标识列表结束（必须添加）
};
MODULE_DEVICE_TABLE(of, led_of_match);  // 向内核注册匹配表，供总线匹配使用

// 4. Platform驱动结构体：关联probe、remove和匹配表
static struct platform_driver led_platform_driver = {
    .probe = led_platform_probe,
    .remove = led_platform_remove,
    .driver = {
        .name = "led-platform-drv",  // 驱动名，可通过modprobe按名加载
        .of_match_table = led_of_match,  // 关联设备树匹配表（核心）
        .owner = THIS_MODULE,
    },
};

// 5. 模块加载/卸载宏（简化模块初始化代码）
module_platform_driver(led_platform_driver);
MODULE_LICENSE("GPL");  // 必须添加，否则加载时报警告
MODULE_DESCRIPTION("Simple Platform Bus LED Driver");
```
关键代码解析：
- `of_get_named_gpio_flags`：从设备树解析GPIO引脚号的核心API，替代手动指定引脚，实现“硬件配置与代码分离”；
- `devm_gpio_request`：带资源管理的GPIO申请函数，驱动卸载时无需手动调用`gpio_free`，由内核自动释放，减少资源泄漏风险；
- `module_platform_driver`：内核提供的宏，自动实现`module_init`和`module_exit`，简化代码。

3. 优化后完整驱动代码（led_platform_opt.c）
```c
#include <linux/init.h>
#include <linux/module.h>
#include <linux/platform_device.h>
#include <linux/of.h>
#include <linux/gpio.h>
#include <linux/of_gpio.h>
#include <linux/sysfs.h>  // sysfs相关API
#include <linux/delay.h>  // 延时API

// 定义LED设备私有数据结构体：存储所有资源和状态
struct led_private_data {
    int led_gpio;          // GPIO引脚号
    int brightness;        // 亮度值（0-10，0熄灭，10最亮）
    struct device *dev;    // 设备结构体指针
};

// sysfs写接口：用户态echo数值时调用，调节亮度
static ssize_t brightness_store(struct device *dev, struct device_attribute *attr,
                                const char *buf, size_t count)
{
    struct led_private_data *priv = dev_get_drvdata(dev);  // 获取私有数据
    int brightness;

    // 解析用户态传入的亮度值（0-10）
    if (kstrtoint(buf, 10, &brightness) < 0) {
        dev_err(dev, "invalid brightness value\n");
        return -EINVAL;
    }
    // 亮度值范围检查
    priv->brightness = clamp_val(brightness, 0, 10);

    // 软件模拟亮度调节：通过占空比实现（亮度越高，亮的时间越长）
    if (priv->brightness == 0) {
        gpio_set_value(priv->gpio, 1);  // 熄灭
    } else {
        // 循环10次，亮的次数=亮度值，暗的次数=10-亮度值
        for (int i = 0; i < 10; i++) {
            gpio_set_value(priv->led_gpio, (i < priv->brightness) ? 0 : 1);
            msleep(10);  // 延时10ms，避免闪烁过快
        }
    }
    dev_info(dev, "set brightness: %d\n", priv->brightness);
    return count;
}

// sysfs读接口：用户态cat时调用，返回当前亮度
static ssize_t brightness_show(struct device *dev, struct device_attribute *attr,
                               char *buf)
{
    struct led_private_data *priv = dev_get_drvdata(dev);
    return sprintf(buf, "%d\n", priv->brightness);
}

// 定义sysfs属性：亮度调节节点
static DEVICE_ATTR_RW(brightness);

// probe函数：初始化私有数据、资源和sysfs
static int led_platform_probe(struct platform_device *pdev)
{
    // 1. 分配私有数据（devm_前缀，自动释放）
    struct led_private_data *priv = devm_kzalloc(&pdev->dev, sizeof(*priv), GFP_KERNEL);
    if (!priv) return -ENOMEM;

    // 2. 解析设备树和GPIO（同之前逻辑）
    priv->dev = &pdev->dev;
    priv->led_gpio = of_get_named_gpio_flags(pdev->dev.of_node, "led-gpio", 0, NULL);
    if (!gpio_is_valid(priv->led_gpio)) return -EINVAL;
    if (devm_gpio_request(&pdev->dev, priv->led_gpio, "led-platform") < 0)
        return -EBUSY;
    gpio_direction_output(priv->led_gpio, 1);
    priv->brightness = 5;  // 默认亮度5

    // 3. 创建设备类和sysfs节点（自动在/sys/class/下生成led-platform目录）
    pdev->dev.class = class_create(THIS_MODULE, "led-platform");
    if (IS_ERR(pdev->dev.class)) return PTR_ERR(pdev->dev.class);
    // 创建设备文件（/sys/class/led-platform/led@0/brightness）
    if (device_create(pdev->dev.class, &pdev->dev, 0, priv, "led@0") < 0)
        return -ENODEV;

    // 4. 注册sysfs亮度属性
    if (device_create_file(&pdev->dev, &dev_attr_brightness) < 0) {
        dev_err(&pdev->dev, "create sysfs file failed\n");
        return -ENODEV;
    }

    // 5. 绑定私有数据到设备
    dev_set_drvdata(&pdev->dev, priv);
    dev_info(&pdev->dev, "probe success: brightness=%d\n", priv->brightness);
    return 0;
}

// remove函数：清理sysfs节点（devres自动释放其他资源）
static int led_platform_remove(struct platform_device *pdev)
{
    device_remove_file(&pdev->dev, &dev_attr_brightness);
    device_destroy(pdev->dev.class, 0);
    class_destroy(pdev->dev.class);
    dev_info(&pdev->dev, "remove success\n");
    return 0;
}

// 匹配表和驱动结构体（同之前，省略重复代码）
static const struct of_device_id led_of_match[] = {
    { .compatible = "demo,led-platform" },
    { /* Sentinel */ }
};
MODULE_DEVICE_TABLE(of, led_of_match);

static struct platform_driver led_platform_driver = {
    .probe = led_platform_probe,
    .remove = led_platform_remove,
    .driver = {
        .name = "led-platform-opt",
        .of_match_table = led_of_match,
        .owner = THIS_MODULE,
    },
};

module_platform_driver(led_platform_driver);
MODULE_LICENSE("GPL");
MODULE_DESCRIPTION("Optimized Platform Bus LED Driver with Sysfs");
```

2. 实战优化：驱动中实现GPIO低功耗模式
需先通过内核配置启用GPIO低功耗支持，再在驱动中调用低功耗API。

步骤1：内核配置GPIO低功耗支持
```bash
# 进入内核源码目录，打开图形化配置
make menuconfig
# 配置路径：
# Device Drivers → GPIO Support → Enable GPIO power management (PM) support
# 选中该选项（按Y），保存并退出
# 重新编译内核和模块
make ARCH=arm CROSS_COMPILE=arm-linux-gnueabihf- modules -j4
```

步骤2：驱动中添加低功耗逻辑（关键代码片段）
在之前优化驱动的基础上，添加“定时器监测闲置时间”和“GPIO低功耗配置”：
```c
#include <linux/pm_runtime.h>  // 电源管理Runtime PM API

// 1. 初始化时启用Runtime PM
static int led_platform_probe(struct platform_device *pdev)
{
    // ... 省略之前的初始化代码 ...

    // 启用Runtime PM（运行时电源管理）
    pm_runtime_enable(&pdev->dev);
    pm_runtime_set_active(&pdev->dev);
    pm_runtime_get_sync(&pdev->dev);  // 初始为活跃状态

    // 初始化闲置监测定时器（10秒无操作则进入低功耗）
    devm_timer_setup(&pdev->dev, &priv->idle_timer, idle_timer_func, 0);
    mod_timer(&priv->idle_timer, jiffies + 10 * HZ);  // 10秒后触发

    return 0;
}

// 2. 定时器回调函数：闲置时进入低功耗
static void idle_timer_func(struct timer_list *t)
{
    struct led_private_data *priv = from_timer(priv, t, idle_timer);
    struct gpio_chip *chip = gpio_to_chip(priv->led_gpio);

    // 若亮度为0（熄灭）且10秒无操作，配置GPIO为休眠模式
    if (priv->brightness == 0) {
        // 步骤1：关闭GPIO输出（设置为输入高阻态）
        gpio_direction_input(priv->led_gpio);
        // 步骤2：配置GPIO控制器进入休眠模式（全志H3专用API，需查硬件手册）
        chip->set_wake(priv->led_gpio, 0);  // 禁用唤醒功能
        chip->power_off(chip);              // 关闭GPIO模块电源
        pm_runtime_put_sync(priv->dev);     // 进入低功耗状态
        dev_info(priv->dev, "enter low power mode\n");
    } else {
        // 有操作，重新启动定时器
        mod_timer(t, jiffies + 10 * HZ);
    }
}

// 3. sysfs写接口中恢复普通模式
static ssize_t brightness_store(struct device *dev, struct device_attribute *attr,
                                const char *buf, size_t count)
{
    struct led_private_data *priv = dev_get_drvdata(dev);
    struct gpio_chip *chip = gpio_to_chip(priv->led_gpio);

    // 若当前为低功耗模式，先恢复
    if (pm_runtime_suspended(dev)) {
        pm_runtime_get_sync(dev);          // 唤醒设备
        chip->power_on(chip);              // 开启GPIO电源
        chip->set_wake(priv->led_gpio, 1); // 启用GPIO功能
        gpio_direction_output(priv->led_gpio, 1);  // 恢复输出模式
        dev_info(dev, "exit low power mode\n");
    }

    // ... 省略亮度调节代码 ...

    // 重新启动闲置定时器
    mod_timer(&priv->idle_timer, jiffies + 10 * HZ);
    return count;
}

// 4. 卸载时禁用PM
static int led_platform_remove(struct platform_device *pdev)
{
    pm_runtime_disable(&pdev->dev);
    // ... 省略其他清理代码 ...
    return 0;
}
```

