2. 步骤1：编写I2C从设备设备树节点（基于全志H3）
需在I2C主控制器节点（如`i2c1`）下添加传感器子节点，指定从设备地址、兼容标识、供电等信息：
```dts
/dts-v1/;
#include "sun8i-h3.dtsi"

/ {
    // ... 省略其他节点 ...

    /* I2C主控制器节点（内核已在sun8i-h3.dtsi中定义，此处仅展示子节点） */
    i2c1: i2c@01c2b000 {
        status = "okay";  // 启用I2C1控制器
        clock-frequency = <400000>;  // 总线速率400kHz（快速模式）

        /* BMI160传感器子节点（从设备） */
        bmi160@68 {
            compatible = "bosch,bmi160";  // 兼容标识，驱动匹配用
            reg = <0x68>;  // 7位从设备地址（与硬件SDO引脚连接一致）
            status = "okay";
            vdd-supply = <&reg_3v3>;  // 传感器供电（3.3V）
            vddio-supply = <&reg_3v3>;  // I/O引脚供电（3.3V）
        };
    };
};
```
关键属性解析：
- `reg = <0x68>`：从设备地址（7位），必须与硬件接线的SDO引脚状态一致；
- `clock-frequency = <400000>`：I2C总线速率，常见有100kHz（标准模式）和400kHz（快速模式），需与传感器支持的速率匹配；
- `compatible = "bosch,bmi160"`：驱动匹配标识，若用内核自带BMI160驱动需用此值，自定义驱动可自行定义。

3. 步骤2：搭建`i2c_driver`驱动框架（自定义BMI160驱动）
从设备驱动核心是实现`i2c_driver`结构体，包含匹配表、`probe`（初始化）、`remove`（清理）函数，调用主设备API与传感器通信。

框架代码如下（bmi160_i2c_drv.c）：
```c
#include <linux/init.h>
#include <linux/module.h>
#include <linux/i2c.h>          // I2C核心头文件
#include <linux/of.h>           // 设备树解析
#include <linux/of_device.h>    // 设备树匹配
#include <linux/devm.h>         // 资源管理

// 传感器私有数据结构体：存储设备信息和状态
struct bmi160_data {
    struct i2c_client *client;  // I2C从设备客户端结构体（核心，关联主设备）
    int accel_x;                // 加速度计X轴数据
    int gyro_x;                 // 陀螺仪X轴数据
};

// 1. probe函数：设备与驱动匹配成功后调用，初始化传感器
static int bmi160_probe(struct i2c_client *client, const struct i2c_device_id *id)
{
    struct bmi160_data *data;
    int ret;

    // 检查I2C主设备是否支持所需功能（如快速模式）
    if (!i2c_check_functionality(client->adapter, I2C_FUNC_I2C)) {
        dev_err(&client->dev, "i2c adapter not support I2C_FUNC_I2C\n");
        return -EOPNOTSUPP;
    }

    // 分配私有数据（devm_前缀，自动释放）
    data = devm_kzalloc(&client->dev, sizeof(*data), GFP_KERNEL);
    if (!data) return -ENOMEM;

    // 绑定私有数据到i2c_client（后续可通过dev_get_drvdata获取）
    data->client = client;
    i2c_set_clientdata(client, data);

    // TODO：后续章节实现：传感器初始化（如写配置寄存器）
    dev_info(&client->dev, "probe success: i2c address=0x%x\n", client->addr);
    return 0;
}

// 2. remove函数：驱动卸载或设备移除时调用，清理资源
static int bmi160_remove(struct i2c_client *client)
{
    struct bmi160_data *data = i2c_get_clientdata(client);
    dev_info(&client->dev, "remove success: addr=0x%x\n", data->client->addr);
    return 0;
}

// 3. 传统匹配表（基于从设备地址，无设备树时使用）
static const struct i2c_device_id bmi160_id_table[] = {
    { "bmi160", 0 },  // 驱动名，与i2c_driver.name一致
    { /* Sentinel */ }
};
MODULE_DEVICE_TABLE(i2c, bmi160_id_table);

// 4. 设备树匹配表（基于compatible，推荐使用）
static const struct of_device_id bmi160_of_match[] = {
    { .compatible = "bosch,bmi160" },  // 与设备树节点compatible一致
    { /* Sentinel */ }
};
MODULE_DEVICE_TABLE(of, bmi160_of_match);

// 5. I2C驱动核心结构体
static struct i2c_driver bmi160_i2c_driver = {
    .probe = bmi160_probe,
    .remove = bmi160_remove,
    .id_table = bmi160_id_table,    // 传统地址匹配表
    .driver = {
        .name = "bmi160-i2c-drv",   // 驱动名，可通过modprobe加载
        .of_match_table = bmi160_of_match,  // 设备树匹配表（优先级更高）
        .owner = THIS_MODULE,
    },
};

// 6. 模块加载/卸载宏（简化初始化）
module_i2c_driver(bmi160_i2c_driver);
MODULE_LICENSE("GPL");
MODULE_DESCRIPTION("BMI160 I2C Sensor Driver Framework");
```
框架核心解析：
- `i2c_client`：
代表I2C从设备，由内核解析设备树后生成，包含从设备地址、主设备适配器（`adapter`）等关键信息，是驱动与主设备通信的桥梁；

- `i2c_check_functionality`：
检查主设备是否支持所需通信功能（如`I2C_FUNC_I2C`表示支持标准I2C时序），避免主从设备功能不匹配；

- `module_i2c_driver`：
内核提供的宏，自动实现`module_init`和`module_exit`，简化代码（等价于注册/注销`i2c_driver`）。

1. 核心通信API解析：`i2c_transfer`

`i2c_transfer`是I2C主设备提供的最核心通信函数，用于执行一个或多个I2C消息（`struct i2c_msg`），实现任意读写逻辑。
函数原型及关键参数：
```c
// 函数原型：执行I2C消息数组，返回成功执行的消息数（失败返回负数）
int i2c_transfer(struct i2c_adapter *adap, struct i2c_msg *msgs, int num);

// I2C消息结构体：描述单次读写操作的信息
struct i2c_msg {
    __u16 addr;     // 从设备地址（7位，无需带读写位）
    __u16 flags;    // 操作标志：0表示写，I2C_M_RD表示读
    __u16 len;      // 数据长度（字节数）
    __u8 *buf;      // 数据缓冲区（写时存要发送的数据，读时存接收的数据）
};
```

关键注意：
- `addr`是7位从设备地址，无需拼接读写位（`flags`中的`I2C_M_RD`自动控制读写）；
- 多个`i2c_msg`可组成“消息链”，`i2c_transfer`会按顺序执行，中间不插入停止信号（如“写寄存器地址→读数据”可合并为一个消息链，提升效率）；
- 返回值：成功返回执行的消息数（如2个消息返回2），失败返回负数错误码（如`-ETIMEDOUT`表示超时）。

2. 实战实现1：传感器初始化（写配置寄存器）
传感器必须通过配置寄存器启用功能（如设置采样率、量程）。

以BMI160为例，需先写“电源管理寄存器”启用加速度计和陀螺仪，再写“配置寄存器”设置量程：
- BMI160关键寄存器映射（部分）：
  | 寄存器地址 | 名称         | 功能说明                                  | 配置值示例                  |
  |------------|--------------|-------------------------------------------|-----------------------------|
  | 0x7E       | CMD          | 命令寄存器：发送命令初始化传感器          | 0x11（启用加速度计）        |
  | 0x40       | ACC_CONF     | 加速度计配置：量程+采样率                 | 0x08（±4g量程，100Hz采样）  |
  | 0x41       | GYR_CONF     | 陀螺仪配置：量程+采样率                   | 0x08（±2000°/s量程，100Hz） |

初始化代码实现（在`bmi160_probe`函数中添加）：
```c
#include <linux/delay.h>  // 延时函数

// 1. 写单个寄存器（封装函数，便于调用）
static int bmi160_write_reg(struct bmi160_data *data, u8 reg, u8 value)
{
    struct i2c_client *client = data->client;
    struct i2c_msg msg;
    u8 buf[2];  // buf[0]：寄存器地址，buf[1]：要写入的值

    buf[0] = reg;
    buf[1] = value;

    // 构造写消息：地址=client->addr，标志=0（写），长度=2，缓冲区=buf
    msg.addr = client->addr;
    msg.flags = 0;
    msg.len = sizeof(buf);
    msg.buf = buf;

    // 执行单个消息的写操作
    return i2c_transfer(client->adapter, &msg, 1);
}

// 2. 传感器初始化函数（在probe中调用）
static int bmi160_init(struct bmi160_data *data)
{
    int ret;

    // 步骤1：发送命令启用加速度计（等待传感器上电稳定，延时100ms）
    msleep(100);
    ret = bmi160_write_reg(data, 0x7E, 0x11);  // CMD=0x11：启用加速度计
    if (ret != 1) {  // 成功返回1（执行1个消息）
        dev_err(&data->client->dev, "enable accel failed: %d\n", ret);
        return ret;
    }

    // 步骤2：发送命令启用陀螺仪
    msleep(10);
    ret = bmi160_write_reg(data, 0x7E, 0x12);  // CMD=0x12：启用陀螺仪
    if (ret != 1) {
        dev_err(&data->client->dev, "enable gyro failed: %d\n", ret);
        return ret;
    }

    // 步骤3：配置加速度计量程为±4g，采样率100Hz（ACC_CONF=0x08）
    msleep(10);
    ret = bmi160_write_reg(data, 0x40, 0x08);
    if (ret != 1) {
        dev_err(&data->client->dev, "config accel failed: %d\n", ret);
        return ret;
    }

    // 步骤4：配置陀螺仪量程为±2000°/s，采样率100Hz（GYR_CONF=0x08）
    msleep(10);
    ret = bmi160_write_reg(data, 0x41, 0x08);
    if (ret != 1) {
        dev_err(&data->client->dev, "config gyro failed: %d\n", ret);
        return ret;
    }

    dev_info(&data->client->dev, "init success: accel/gyro enabled\n");
    return 0;
}

// 3. 在probe函数中调用初始化函数
static int bmi160_probe(struct i2c_client *client, const struct i2c_device_id *id)
{
    // ... 省略之前的私有数据分配代码 ...

    // 调用传感器初始化函数
    ret = bmi160_init(data);
    if (ret) return ret;

    dev_info(&client->dev, "probe success: i2c address=0x%x\n", client->addr);
    return 0;
}
```

3. 实战实现2：读取传感器数据（读数据寄存器）
BMI160的加速度计和陀螺仪数据存储在连续的“数据寄存器”中，可通过“写寄存器地址→读数据”的消息链批量读取：
- 数据寄存器映射：
  | 寄存器地址 | 名称       | 功能说明                  | 数据长度 |
  |------------|------------|---------------------------|----------|
  | 0x04       | ACC_X_L    | 加速度计X轴低8位          | 1字节    |
  | 0x05       | ACC_X_H    | 加速度计X轴高8位          | 1字节    |
  | 0x06       | ACC_Y_L    | 加速度计Y轴低8位          | 1字节    |
  | 0x07       | ACC_Y_H    | 加速度计Y轴高8位          | 1字节    |
  | 0x08       | ACC_Z_L    | 加速度计Z轴低8位          | 1字节    |
  | 0x09       | ACC_Z_H    | 加速度计Z轴高8位          | 1字节    |
  | 0x0A       | GYR_X_L    | 陀螺仪X轴低8位            | 1字节    |
  | 0x0B       | GYR_X_H    | 陀螺仪X轴高8位            | 1字节    |

数据读取与解析代码（添加到驱动中）：
```c
// 1. 读多个连续寄存器（消息链：写地址→读数据）
static int bmi160_read_regs(struct bmi160_data *data, u8 reg, u8 *buf, int len)
{
    struct i2c_client *client = data->client;
    struct i2c_msg msgs[2];  // 2个消息：写地址+读数据
    int ret;

    // 消息1：写要读取的起始寄存器地址
    msgs[0].addr = client->addr;
    msgs[0].flags = 0;        // 写操作
    msgs[0].len = 1;          // 地址长度1字节
    msgs[0].buf = &reg;       // 要读取的起始寄存器地址

    // 消息2：从起始地址开始读len字节数据
    msgs[1].addr = client->addr;
    msgs[1].flags = I2C_M_RD; // 读操作
    msgs[1].len = len;        // 要读取的数据长度
    msgs[1].buf = buf;        // 存储读取数据的缓冲区

    // 执行消息链（2个消息）
    ret = i2c_transfer(client->adapter, msgs, 2);
    if (ret != 2) {  // 成功返回2（2个消息均执行完成）
        dev_err(&client->dev, "read regs failed: ret=%d, reg=0x%x\n", ret, reg);
        return ret < 0 ? ret : -EIO;
    }
    return 0;
}

// 2. 数据解析：将16位原始数据转换为物理量
#define ACC_SCALE_4G  (4.0f / 32768.0f)   // ±4g量程：1LSB = 4g/32768
#define GYR_SCALE_2000DPS  (2000.0f / 32768.0f)  // ±2000°/s量程：1LSB=2000°/s/32768

static int bmi160_read_data(struct bmi160_data *data)
{
    u8 buf[8];  // 存储8字节数据（X/Y/Z加速度+X陀螺仪）
    s16 accel_x_raw, gyro_x_raw;  // 16位有符号原始数据
    float accel_x, gyro_x;        // 转换后的物理量

    // 步骤1：读取8字节数据（从0x04开始）
    int ret = bmi160_read_regs(data, 0x04, buf, 8);
    if (ret) return ret;

    // 步骤2：拼接低8位和高8位为16位有符号数据（小端模式）
    accel_x_raw = (s16)((buf[1] << 8) | buf[0]);  // ACC_X_H <<8 + ACC_X_L
    gyro_x_raw = (s16)((buf[7] << 8) | buf[6]);   // GYR_X_H <<8 + GYR_X_L

    // 步骤3：转换为物理量
    accel_x = accel_x_raw * ACC_SCALE_4G;  // 单位：g（1g=9.8m/s²）
    gyro_x = gyro_x_raw * GYR_SCALE_2000DPS;  // 单位：°/s

    // 步骤4：存储到私有数据并打印日志（调试用）
    data->accel_x = accel_x * 9.8f;  // 转换为m/s²
    data->gyro_x = gyro_x;
    dev_info(&data->client->dev, "accel_x=%.2f m/s², gyro_x=%.2f °/s\n",
             data->accel_x, data->gyro_x);

    return 0;
}

// 3. 添加定时器，周期性读取数据（probe中初始化）
static struct timer_list data_timer;
static void data_timer_func(struct timer_list *t)
{
    struct bmi160_data *data = from_timer(data, t, data_timer);
    bmi160_read_data(data);
    mod_timer(t, jiffies + HZ);  // 1秒读取一次
}

// 在probe函数中添加定时器初始化
static int bmi160_probe(struct i2c_client *client, const struct i2c_device_id *id)
{
    // ... 省略之前的代码 ...

    // 初始化定时器（1秒读取一次数据）
    timer_setup(&data->data_timer, data_timer_func, 0);
    mod_timer(&data->data_timer, jiffies + HZ);

    dev_info(&client->dev, "probe success: i2c address=0x%x\n", client->addr);
    return 0;
}

// 在私有数据结构体中添加定时器成员
struct bmi160_data {
    struct i2c_client *client;
    int accel_x;
    int gyro_x;
    struct timer_list data_timer;  // 新增定时器成员
};
```

2. 实战优化代码实现（基于前文驱动）
优化点1：超时配置与重传机制（增强`bmi160_read_regs`函数）
```c
#include <linux/of.h>

// 1. 从设备树读取超时和重传参数（灵活配置，无需改代码）
#define BMI160_DEFAULT_TIMEOUT 100  // 默认超时100ms
#define BMI160_DEFAULT_RETRY 3      // 默认重传3次

static int bmi160_parse_dt(struct bmi160_data *data)
{
    struct device *dev = &data->client->dev;
    struct device_node *np = dev->of_node;

    // 从设备树读取超时时间（ms），无配置则用默认值
    of_property_read_u32(np, "i2c-timeout-ms", &data->timeout);
    if (!data->timeout) data->timeout = BMI160_DEFAULT_TIMEOUT;

    // 从设备树读取重传次数，无配置则用默认值
    of_property_read_u32(np, "i2c-retry-count", &data->retry);
    if (!data->retry) data->retry = BMI160_DEFAULT_RETRY;

    dev_info(dev, "dt config: timeout=%dms, retry=%d\n",
             data->timeout, data->retry);
    return 0;
}

// 2. 带超时和重传的读寄存器函数
static int bmi160_read_regs(struct bmi160_data *data, u8 reg, u8 *buf, int len)
{
    struct i2c_client *client = data->client;
    struct i2c_msg msgs[2];
    int ret, retry;
    unsigned long timeout_jiffies = msecs_to_jiffies(data->timeout);

    // 构造消息链（同之前）
    msgs[0].addr = client->addr;
    msgs[0].flags = 0;
    msgs[0].len = 1;
    msgs[0].buf = &reg;
    msgs[1].addr = client->addr;
    msgs[1].flags = I2C_M_RD;
    msgs[1].len = len;
    msgs[1].buf = buf;

    // 重传机制：最多重试data->retry次
    for (retry = 0; retry < data->retry; retry++) {
        // 带超时的i2c_transfer（核心优化：超时返回-ETIMEDOUT）
        ret = i2c_transfer_with_timeout(client->adapter, msgs, 2, timeout_jiffies);
        if (ret == 2) {  // 成功
            if (retry > 0) {
                dev_warn(&client->dev, "read success after %d retries\n", retry);
            }
            return 0;
        }
        // 超时或其他错误，延时后重试
        dev_dbg(&client->dev, "read retry %d/%d, ret=%d\n", retry+1, data->retry, ret);
        msleep(10);  // 延时10ms，避免频繁重试
    }

    // 多次重试失败
    dev_err(&client->dev, "read failed after %d retries, reg=0x%x\n", data->retry, reg);
    return ret < 0 ? ret : -EIO;
}

// 3. 在私有数据结构体中添加配置成员
struct bmi160_data {
    struct i2c_client *client;
    int accel_x;
    int gyro_x;
    struct timer_list data_timer;
    u32 timeout;     // 超时时间（ms）
    u32 retry;       // 重传次数
};

// 4. 在probe函数中调用设备树解析函数
static int bmi160_probe(struct i2c_client *client, const struct i2c_device_id *id)
{
    // ... 省略之前的代码 ...

    // 解析设备树配置的超时和重传参数
    bmi160_parse_dt(data);

    // ... 省略后续代码 ...
}
```

优化点2：错误恢复机制（传感器重置）
```c
// 1. 传感器重置函数（写复位寄存器）
static int bmi160_reset(struct bmi160_data *data)
{
    int ret;

    dev_warn(&data->client->dev, "reset sensor...\n");
    // 写复位命令（BMI160复位寄存器为0x7E，命令0xB6）
    ret = bmi160_write_reg(data, 0x7E, 0xB6);
    if (ret != 1) {
        dev_err(&data->client->dev, "reset failed: %d\n", ret);
        return ret;
    }
    msleep(200);  // 等待复位完成（传感器手册要求至少100ms）
    // 复位后重新初始化传感器
    return bmi160_init(data);
}

// 2. 在数据读取函数中添加错误恢复逻辑
static int bmi160_read_data(struct bmi160_data *data)
{
    static int error_count = 0;  // 连续错误计数
    int ret = bmi160_read_regs(data, 0x04, data->buf, 8);

    if (ret == 0) {
        error_count = 0;  // 读取成功，重置错误计数
        // ... 省略数据解析代码 ...
        return 0;
    }

    // 读取失败，累计错误计数
    error_count++;
    if (error_count >= 5) {  // 连续5次失败，执行重置
        ret = bmi160_reset(data);
        if (ret == 0) {
            error_count = 0;
            dev_info(&data->client->dev, "reset success, resume read\n");
        }
    }
    return ret;
}
```

