2. 实战：编写基础`pci_driver`驱动（以虚拟PCIe设备为例）
假设开发板存在一个PCIe端点设备（Vendor ID=0x1234，Device ID=0x5678），驱动实现“注册→匹配→BAR映射”核心流程：

（1）驱动代码（pcie_demo_drv.c）
```c
#include <linux/init.h>
#include <linux/module.h>
#include <linux/pci.h>          // PCIe核心头文件
#include <linux/io.h>           // ioremap相关API
#include <linux/of.h>           // 设备树匹配

// 设备私有数据：存储BAR虚拟地址、设备结构体等
struct pcie_demo_data {
    struct pci_dev *pdev;       // PCIe设备结构体（代表枚举后的设备）
    void __iomem *bar0_virt;    // BAR0的虚拟地址（CPU可访问）
    resource_size_t bar0_phys;  // BAR0的物理地址（从设备获取）
    resource_size_t bar0_size;  // BAR0的大小
};

// 1. probe函数：设备与驱动匹配成功后调用，核心是初始化硬件
static int pcie_demo_probe(struct pci_dev *pdev, const struct pci_device_id *id)
{
    struct pcie_demo_data *data;
    int ret;

    // 步骤1：分配私有数据（devm_前缀自动释放）
    data = devm_kzalloc(&pdev->dev, sizeof(*data), GFP_KERNEL);
    if (!data) return -ENOMEM;
    data->pdev = pdev;
    pci_set_drvdata(pdev, data);  // 绑定私有数据到pci_dev

    // 步骤2：使能PCIe设备（必须先执行，否则无法访问BAR空间）
    ret = pci_enable_device(pdev);
    if (ret) {
        dev_err(&pdev->dev, "enable device failed: %d\n", ret);
        return ret;
    }

    // 步骤3：禁用PCIe总线的缓存一致性（根据设备需求，部分设备需启用）
    pci_set_master(pdev);  // 允许设备作为DMA主设备（后续DMA传输需此步骤）
    pci_try_set_mwi(pdev); // 尝试启用内存写合并（提升写入性能）

    // 步骤4：获取BAR0的物理地址和大小（从pci_dev中读取枚举结果）
    data->bar0_phys = pci_resource_start(pdev, 0);  // BAR0的物理基地址
    data->bar0_size = pci_resource_len(pdev, 0);    // BAR0的大小
    if (!data->bar0_size) {
        dev_err(&pdev->dev, "BAR0 size is 0\n");
        ret = -EINVAL;
        goto disable_device;
    }

    // 步骤5：将BAR0的物理地址映射为虚拟地址（CPU可访问）
    data->bar0_virt = devm_ioremap_resource(&pdev->dev, &pdev->resource[0]);
    if (IS_ERR(data->bar0_virt)) {
        ret = PTR_ERR(data->bar0_virt);
        dev_err(&pdev->dev, "ioremap BAR0 failed: %d\n", ret);
        goto disable_device;
    }

    // 步骤6：验证BAR映射（读写BAR0寄存器，假设0x00为测试寄存器）
    u32 val = ioread32(data->bar0_virt + 0x00);  // 读BAR0偏移0x00的值
    dev_info(&pdev->dev, "BAR0: phys=0x%lx, size=0x%lx, val=0x%x\n",
             data->bar0_phys, data->bar0_size, val);
    iowrite32(0x12345678, data->bar0_virt + 0x00);  // 写测试值到寄存器
    val = ioread32(data->bar0_virt + 0x00);
    dev_info(&pdev->dev, "write test: val=0x%x\n", val);

    return 0;

// 错误处理：步骤失败后回滚
disable_device:
    pci_disable_device(pdev);
    return ret;
}

// 2. remove函数：驱动卸载或设备移除时调用，清理资源
static void pcie_demo_remove(struct pci_dev *pdev)
{
    struct pcie_demo_data *data = pci_get_drvdata(pdev);
    // 写0到测试寄存器，恢复设备状态
    iowrite32(0x00000000, data->bar0_virt + 0x00);
    // 禁用设备（devm_自动释放ioremap和私有数据）
    pci_disable_device(pdev);
    dev_info(&pdev->dev, "remove success\n");
}

// 3. 设备ID匹配表（传统匹配方式，无设备树时使用）
static const struct pci_device_id pcie_demo_id_table[] = {
    { PCI_DEVICE(0x1234, 0x5678) },  // Vendor ID=0x1234，Device ID=0x5678
    { /* Sentinel */ }
};
MODULE_DEVICE_TABLE(pci, pcie_demo_id_table);

// 4. 设备树匹配表（推荐，支持设备树动态配置）
static const struct of_device_id pcie_demo_of_match[] = {
    { .compatible = "demo,pcie-demo" },
    { /* Sentinel */ }
};
MODULE_DEVICE_TABLE(of, pcie_demo_of_match);

// 5. PCIe驱动核心结构体
static struct pci_driver pcie_demo_driver = {
    .name = "pcie-demo-drv",       // 驱动名，可通过modprobe加载
    .id_table = pcie_demo_id_table,// 设备ID匹配表
    .probe = pcie_demo_probe,
    .remove = pcie_demo_remove,
    .driver = {
        .of_match_table = pcie_demo_of_match,  // 设备树匹配表
        .owner = THIS_MODULE,
    },
};

// 6. 模块加载/卸载宏
module_pci_driver(pcie_demo_driver);
MODULE_LICENSE("GPL");
MODULE_DESCRIPTION("PCIe Demo Driver (BAR Mapping)");
```

2. 实战：基于`dmaengine`的PCIe DMA传输实现
在之前BAR映射驱动的基础上，添加DMA传输功能，实现“PCIe设备→系统内存”的高速数据读取（以传输1MB数据为例）：

（1）驱动代码扩展（关键部分）
```c
#include <linux/dmaengine.h>      // dmaengine框架头文件
#include <linux/dma-mapping.h>    // DMA缓存一致性头文件

// 扩展私有数据结构体，添加DMA相关成员
struct pcie_demo_data {
    struct pci_dev *pdev;
    void __iomem *bar0_virt;
    resource_size_t bar0_phys;
    resource_size_t bar0_size;

    struct dma_chan *dma_chan;    // DMA通道
    dma_addr_t dma_buf_phys;      // DMA缓冲区物理地址（设备可访问）
    void *dma_buf_virt;           // DMA缓冲区虚拟地址（CPU可访问）
    size_t dma_buf_size;          // DMA缓冲区大小（1MB）
};

// 1. DMA传输完成回调函数（可选，异步通知）
static void pcie_dma_complete_func(void *param)
{
    struct pcie_demo_data *data = param;
    dev_info(&data->pdev->dev, "DMA transfer completed\n");
}

// 2. DMA通道初始化（申请通道、配置从设备、分配缓冲区）
static int pcie_dma_init(struct pcie_demo_data *data)
{
    struct dma_slave_config config = {0};
    int ret;

    data->dma_buf_size = 1024 * 1024;  // 1MB DMA缓冲区

    // 步骤1：申请DMA通道（指定传输方向为从设备到内存）
    data->dma_chan = dma_request_chan(&data->pdev->dev, "rx");  // "rx"表示接收（设备→内存）
    if (!data->dma_chan) {
        dev_err(&data->pdev->dev, "request DMA chan failed\n");
        return -ENODEV;
    }

    // 步骤2：配置DMA从设备参数（PCIe设备作为从设备）
    config.direction = DMA_DEV_TO_MEM;  // 传输方向：设备→内存
    config.src_addr = data->bar0_phys + 0x100;  // 源地址：PCIe设备BAR0偏移0x100（数据缓冲区）
    config.src_addr_width = DMA_SLAVE_BUSWIDTH_4_BYTES;  // 源数据宽度：32位
    config.src_maxburst = 16;  // 最大突发长度：16个32位数据（提升效率）
    ret = dmaengine_slave_config(data->dma_chan, &config);
    if (ret) {
        dev_err(&data->pdev->dev, "config DMA slave failed: %d\n", ret);
        goto release_chan;
    }

    // 步骤3：分配DMA缓冲区（需满足缓存一致性，设备可直接访问）
    data->dma_buf_virt = dma_alloc_coherent(&data->pdev->dev, data->dma_buf_size,
                                            &data->dma_buf_phys, GFP_KERNEL);
    if (!data->dma_buf_virt) {
        dev_err(&data->pdev->dev, "alloc DMA buf failed\n");
        ret = -ENOMEM;
        goto release_chan;
    }

    // 步骤4：初始化缓冲区为0（测试用）
    memset(data->dma_buf_virt, 0x00, data->dma_buf_size);
    dev_info(&data->pdev->dev, "DMA init success: buf=0x%lx, size=1MB\n",
             data->dma_buf_phys);
    return 0;

release_chan:
    dma_release_chan(data->dma_chan);
    return ret;
}

// 3. 执行DMA传输（同步传输，等待完成）
static int pcie_dma_transfer(struct pcie_demo_data *data)
{
    struct dma_async_tx_descriptor *desc;  // DMA传输描述符
    dma_cookie_t cookie;
    enum dma_status status;

    // 步骤1：准备DMA传输描述符（指定传输参数）
    desc = dmaengine_prep_slave_single(data->dma_chan,  // DMA通道
                                       data->dma_buf_phys,  // 目的地址：系统内存缓冲区
                                       data->dma_buf_size,  // 传输长度
                                       DMA_DEV_TO_MEM,      // 传输方向
                                       DMA_PREP_INTERRUPT); // 传输完成后触发中断
    if (!desc) {
        dev_err(&data->pdev->dev, "prepare DMA desc failed\n");
        return -EIO;
    }

    // 步骤2：设置传输完成回调函数（可选）
    desc->callback = pcie_dma_complete_func;
    desc->callback_param = data;

    // 步骤3：提交DMA传输并等待完成
    cookie = dmaengine_submit(desc);
    if (dma_submit_error(cookie)) {
        dev_err(&data->pdev->dev, "submit DMA failed\n");
        return -EIO;
    }
    dma_async_issue_pending(data->dma_chan);  // 启动DMA传输

    // 同步等待传输完成（超时时间1秒）
    status = dmaengine_wait_for_async_tx(data->dma_chan, cookie,
                                         DMA_TIMEOUT_USEC(1000000));
    if (status != DMA_SUCCESS) {
        dev_err(&data->pdev->dev, "DMA wait failed: %d\n", status);
        return -ETIMEDOUT;
    }

    // 步骤4：验证传输结果（检查缓冲区前4字节数据）
    u32 *buf = (u32 *)data->dma_buf_virt;
    dev_info(&data->pdev->dev, "DMA transfer success: first 4 bytes=0x%x%x%x%x\n",
             buf[0], buf[1], buf[2], buf[3]);
    return 0;
}

// 4. 在probe函数中调用DMA初始化和传输
static int pcie_demo_probe(struct pci_dev *pdev, const struct pci_device_id *id)
{
    // ... 省略之前的BAR映射代码 ...

    // 初始化DMA
    ret = pcie_dma_init(data);
    if (ret) goto disable_device;

    // 执行DMA传输（1MB数据）
    ret = pcie_dma_transfer(data);
    if (ret) goto free_dma_buf;

    return 0;

// 错误处理回滚
free_dma_buf:
    dma_free_coherent(&data->pdev->dev, data->dma_buf_size,
                      data->dma_buf_virt, data->dma_buf_phys);
release_dma_chan:
    dma_release_chan(data->dma_chan);
disable_device:
    pci_disable_device(pdev);
    return ret;
}

// 5. 在remove函数中释放DMA资源
static void pcie_demo_remove(struct pci_dev *pdev)
{
    struct pcie_demo_data *data = pci_get_drvdata(pdev);
    // 释放DMA缓冲区和通道
    dma_free_coherent(&data->pdev->dev, data->dma_buf_size,
                      data->dma_buf_virt, data->dma_buf_phys);
    dma_release_chan(data->dma_chan);
    // ... 省略其他清理代码 ...
}
``` 

（2）关键技术点解析
- 缓存一致性：`dma_alloc_coherent`分配的缓冲区是“设备可直接访问”的，内核会确保CPU缓存与设备访问的一致性（避免CPU缓存中的旧数据被设备读取）；
- 突发传输：`src_maxburst = 16`表示DMA一次可连续传输16个32位数据（64字节），减少PCIe总线的握手次数，提升带宽；
- 同步vs异步：示例中用`dmaengine_wait_for_async_tx`同步等待传输完成，也可通过回调函数实现异步通知（适合无需等待的场景）。

