2. 错误案例：非幂等性`probe`/`remove`的问题

以USB鼠标驱动为例，非幂等性实现会导致热插拔崩溃：
```c
// 错误：probe函数无状态标记，重复插拔会重复申请内存
static int usb_mouse_probe(struct usb_interface *intf, const struct usb_device_id *id)
{
    struct usb_mouse *mouse;
    // 问题：无状态判断，多次probe会重复分配内存，导致内存泄漏
    mouse = kzalloc(sizeof(*mouse), GFP_KERNEL);
    if (!mouse) return -ENOMEM;
    // 未绑定状态标记到设备...
    dev_info(&intf->dev, "probe success\n");
    return 0;
}

// 错误：remove函数无指针非空判断，重复调用会空指针解引用
static void usb_mouse_remove(struct usb_interface *intf)
{
    struct usb_mouse *mouse = usb_get_intfdata(intf);
    // 问题：mouse可能已被释放（如前一次remove已执行），直接kfree会崩溃
    kfree(mouse);
    dev_info(&intf->dev, "remove success\n");
}
```
问题复现：插入→拔出→再次插入→拔出，第二次`remove`时`mouse`已被第一次`remove`释放，执行`kfree(mouse)`会触发内核Oops

3. 正确实现：幂等性`probe`/`remove`适配
通过“状态标记”“资源指针非空判断”和`devm`（设备管理资源）机制实现幂等性，修改后代码如下：
```c
#include <linux/usb.h>
#include <linux/devm.h>

// 设备私有数据（含状态标记）
struct usb_mouse {
    struct usb_device *udev;
    int initialized;  // 状态标记：0=未初始化，1=已初始化
};

// 正确：probe函数添加状态标记，避免重复初始化
static int usb_mouse_probe(struct usb_interface *intf, const struct usb_device_id *id)
{
    struct usb_device *udev = interface_to_usbdev(intf);
    struct usb_mouse *mouse;
    int ret;

    // 步骤1：通过devm分配私有数据（设备移除时自动释放，减少remove压力）
    mouse = devm_kzalloc(&intf->dev, sizeof(*mouse), GFP_KERNEL);
    if (!mouse) return -ENOMEM;

    // 步骤2：状态标记判断，避免重复初始化
    if (mouse->initialized) {
        dev_warn(&intf->dev, "already initialized\n");
        return 0;
    }

    // 步骤3：初始化硬件（如申请中断、配置端点）
    mouse->udev = udev;
    ret = usb_request_irq(udev, usb_endpoint_num(&intf->cur_altsetting->endpoint[0]),
                          usb_mouse_irq, 0, "usb-mouse", mouse);
    if (ret) {
        dev_err(&intf->dev, "request irq failed: %d\n", ret);
        return ret;
    }

    // 步骤4：标记为已初始化，绑定到设备
    mouse->initialized = 1;
    usb_set_intfdata(intf, mouse);
    dev_info(&intf->dev, "probe success: devnum=%d\n", udev->devnum);
    return 0;
}

// 正确：remove函数添加指针校验和状态重置，支持重复调用
static void usb_mouse_remove(struct usb_interface *intf)
{
    struct usb_mouse *mouse = usb_get_intfdata(intf);
    if (!mouse) {  // 指针非空判断，避免空指针
        dev_warn(&intf->dev, "mouse data is NULL\n");
        return;
    }

    // 步骤1：释放资源（仅释放已申请的资源）
    if (mouse->initialized) {
        usb_free_irq(mouse->udev, usb_endpoint_num(&intf->cur_altsetting->endpoint[0]), mouse);
        mouse->initialized = 0;  // 重置状态，支持下次probe
    }

    // 步骤2：devm分配的资源无需手动kfree，设备移除时自动释放
    dev_info(&intf->dev, "remove success: devnum=%d\n", mouse->udev->devnum);
}

// USB设备ID匹配表（鼠标设备）
static const struct usb_device_id usb_mouse_id_table[] = {
    { USB_INTERFACE_INFO(USB_INTERFACE_CLASS_HID, USB_INTERFACE_SUBCLASS_BOOT, USB_INTERFACE_PROTOCOL_MOUSE) },
    { /* Sentinel */ }
};
MODULE_DEVICE_TABLE(usb, usb_mouse_id_table);

// USB驱动结构体
static struct usb_driver usb_mouse_driver = {
    .name = "usb-mouse-drv",
    .probe = usb_mouse_probe,
    .remove = usb_mouse_remove,
    .id_table = usb_mouse_id_table,
};
module_usb_driver(usb_mouse_driver);
MODULE_LICENSE("GPL");
```

3. 实战优化：互斥锁+自旋锁防护资源竞争
以USB存储驱动为例，针对“私有数据竞争”和“中断与`remove`竞争”场景，通过分层同步机制实现防护：
```c
#include <linux/mutex.h>
#include <linux/spinlock.h>

struct usb_storage {
    struct usb_device *udev;
    struct mutex dev_mutex;    // 进程上下文互斥锁（保护私有数据）
    spinlock_t irq_spinlock;   // 中断上下文自旋锁（保护寄存器访问）
    int status;                // 设备状态（0=未就绪，1=就绪）
    struct kref ref;           // 引用计数（管理设备生命周期）
};

// 1. 引用计数释放函数（设备最后一次引用时清理资源）
static void usb_storage_release(struct kref *ref)
{
    struct usb_storage *us = container_of(ref, struct usb_storage, ref);
    mutex_destroy(&us->dev_mutex);
    spin_lock_init(&us->irq_spinlock);
    kfree(us);
}

// 2. probe函数：初始化同步机制和引用计数
static int usb_storage_probe(struct usb_interface *intf, const struct usb_device_id *id)
{
    struct usb_storage *us;
    int ret;

    us = kzalloc(sizeof(*us), GFP_KERNEL);
    if (!us) return -ENOMEM;

    // 初始化同步机制
    mutex_init(&us->dev_mutex);
    spin_lock_init(&us->irq_spinlock);
    kref_init(&us->ref);  // 初始化引用计数为1

    // 初始化硬件（加互斥锁，避免与用户态同时访问）
    mutex_lock(&us->dev_mutex);
    us->udev = interface_to_usbdev(intf);
    us->status = 1;  // 标记为就绪
    ret = usb_request_irq(us->udev, ..., usb_storage_irq, 0, "usb-storage", us);
    mutex_unlock(&us->dev_mutex);

    if (ret) goto err_free;
    usb_set_intfdata(intf, us);
    return 0;

err_free:
    kref_put(&us->ref, usb_storage_release);
    return ret;
}

// 3. remove函数：加锁防护，确保资源安全释放
static void usb_storage_remove(struct usb_interface *intf)
{
    struct usb_storage *us = usb_get_intfdata(intf);
    if (!us) return;

    // 步骤1：禁用中断（加自旋锁，避免与中断处理函数竞争）
    unsigned long flags;
    spin_lock_irqsave(&us->irq_spinlock, flags);  // 关中断+加锁
    usb_free_irq(us->udev, ..., us);
    us->status = 0;  // 标记为未就绪
    spin_unlock_irqrestore(&us->irq_spinlock, flags);  // 解锁+开中断

    // 步骤2：释放资源（加互斥锁，避免与用户态sysfs读写竞争）
    mutex_lock(&us->dev_mutex);
    // 释放其他资源（如DMA缓冲区）
    mutex_unlock(&us->dev_mutex);

    // 步骤3：减少引用计数，最后一次引用时自动释放
    kref_put(&us->ref, usb_storage_release);
}

// 4. 中断处理函数：加自旋锁防护寄存器访问
static irqreturn_t usb_storage_irq(int irq, void *dev_id)
{
    struct usb_storage *us = dev_id;
    unsigned long flags;
    u32 reg_val;

    // 加自旋锁，避免与remove函数竞争寄存器
    spin_lock_irqsave(&us->irq_spinlock, flags);
    if (us->status != 1) {  // 检查设备状态，避免操作未就绪设备
        spin_unlock_irqrestore(&us->irq_spinlock, flags);
        return IRQ_NONE;
    }

    // 读写硬件寄存器（受自旋锁保护）
    reg_val = usb_control_msg(us->udev, ...);
    // 处理中断数据...
    spin_unlock_irqrestore(&us->irq_spinlock, flags);

    return IRQ_HANDLED;
}

// 5. sysfs属性读写函数：加互斥锁防护私有数据
static ssize_t status_show(struct device *dev, struct device_attribute *attr, char *buf)
{
    struct usb_storage *us = dev_get_drvdata(dev);
    ssize_t ret;

    // 加互斥锁，避免与probe/remove竞争status变量
    mutex_lock(&us->dev_mutex);
    ret = sprintf(buf, "%d\n", us->status);
    mutex_unlock(&us->dev_mutex);

    return ret;
}
DEVICE_ATTR_RO(status);  // 注册sysfs只读属性
```

2. 异步probe完整实现（以I2C传感器为例）
以耗时2秒的I2C温湿度传感器（如SHT30）为例，实现“异步probe+工作队列”初始化，核心解决“传感器校准阻塞问题”。

（1）驱动代码实现（关键部分）
```c
#include <linux/module.h>
#include <linux/i2c.h>
#include <linux/workqueue.h>
#include <linux/completion.h>

// 设备私有数据（含工作任务、完成量用于状态同步）
struct sht30_data {
    struct i2c_client *client;
    struct work_struct init_work;  // 慢速初始化工作任务
    struct completion init_comp;   // 用于同步初始化完成状态
    int cali_result;               // 校准结果（0=成功，负值=失败）
    bool initialized;              // 初始化状态标记
};

// 3. 慢速初始化任务（工作队列中执行，进程上下文，可睡眠）
static void sht30_init_work_func(struct work_struct *work)
{
    struct sht30_data *data = container_of(work, struct sht30_data, init_work);
    int ret;
    u8 cali_cmd[] = {0x2C, 0x06};  // SHT30校准命令

    dev_info(&data->client->dev, "async init start: calibrating sensor\n");
    msleep(2000);  // 模拟传感器校准耗时2秒（实际为I2C通信校准）

    // 实际硬件校准：向传感器发送校准命令
    ret = i2c_master_send(data->client, cali_cmd, sizeof(cali_cmd));
    if (ret < 0) {
        dev_err(&data->client->dev, "calibrate failed: %d\n", ret);
        data->cali_result = ret;
        goto complete;
    }

    data->cali_result = 0;
    data->initialized = true;
    dev_info(&data->client->dev, "async init completed: success\n");

complete:
    // 通知probe：初始化完成
    complete(&data->init_comp);
}

// 2. probe函数（快速检查+提交异步任务）
static int sht30_probe(struct i2c_client *client, const struct i2c_device_id *id)
{
    struct sht30_data *data;
    int ret;

    // 步骤1：快速前置检查（设备ID验证、私有数据分配，耗时<1ms）
    if (client->addr != 0x44 && client->addr != 0x45) {  // SHT30默认地址
        dev_err(&client->dev, "invalid addr: 0x%x\n", client->addr);
        return -EINVAL;
    }

    // 步骤2：分配并初始化私有数据
    data = devm_kzalloc(&client->dev, sizeof(*data), GFP_KERNEL);
    if (!data) return -ENOMEM;
    data->client = client;
    i2c_set_clientdata(client, data);

    // 步骤3：初始化工作任务和完成量
    INIT_WORK(&data->init_work, sht30_init_work_func);  // 绑定工作函数
    init_completion(&data->init_comp);
    data->cali_result = -EINPROGRESS;  // 标记为初始化中

    // 步骤4：提交工作任务到默认工作队列（system_wq）
    queue_work(system_wq, &data->init_work);

    // 步骤5：返回PROBE_PENDING，告知内核异步初始化中
    dev_info(&client->dev, "sync probe done: async task submitted\n");
    return -EPROBE_DEFER;  // 等价于PROBE_PENDING，内核会等待完成
}

// 4. remove函数（清理异步任务，避免资源泄漏）
static void sht30_remove(struct i2c_client *client)
{
    struct sht30_data *data = i2c_get_clientdata(client);

    // 取消未执行的工作任务（若设备未初始化完成就拔出）
    if (data->cali_result == -EINPROGRESS) {
        cancel_work_sync(&data->init_work);
        dev_info(&client->dev, "async task canceled\n");
    }
    dev_info(&client->dev, "device removed\n");
}

// 1. 驱动结构体（声明异步probe属性）
static struct i2c_driver sht30_driver = {
    .probe = sht30_probe,
    .remove = sht30_remove,
    .id_table = sht30_id_table,
    .driver = {
        .name = "sht30-drv",
        .of_match_table = sht30_of_match,
        .probe_type = PROBE_ASYNCHRONOUS,  // 关键：声明为异步probe
        .owner = THIS_MODULE,
    },
};

module_i2c_driver(sht30_driver);
MODULE_LICENSE("GPL");
MODULE_DESCRIPTION("SHT30 Async Probe Driver");
```

（2）核心代码解析
- 异步声明：`probe_type = PROBE_ASYNCHRONOUS`告知内核该驱动支持异步probe，内核会预留设备资源，等待初始化完成；
- 任务提交：`queue_work(system_wq, &data->init_work)`将慢速任务提交到系统默认工作队列，`system_wq`是内核全局队列，适合通用任务；
- 状态同步：`struct completion`用于“工作任务→probe”的同步，`complete`函数唤醒等待的内核线程；
- 异常处理：`remove`函数中调用`cancel_work_sync`取消未执行的任务，避免设备拔出后工作任务继续执行导致空指针。

3. 实战优化：按键驱动上下文分离实现

以GPIO按键驱动为例，优化前中断上下文执行慢操作，优化后拆分到工作队列：

（1）优化前代码（问题代码）
```c
// 问题：中断上下文执行日志打印（耗时1ms），阻塞其他中断
static irqreturn_t key_irq_handler(int irq, void *dev_id)
{
    struct key_data *data = dev_id;
    int val;

    val = gpio_get_value(data->gpio);  // 快操作（10us）
    // 问题：中断上下文执行printk（日志打印涉及控制台通信，可睡眠）
    dev_info(&data->dev->dev, "key state: %d\n", val);  
    // 问题：中断上下文执行用户态通知（可能睡眠）
