（2）优化后代码（上下文分离）
```c
#include <linux/gpio.h>
#include <linux/interrupt.h>
#include <linux/workqueue.h>

struct key_data {
    struct device *dev;
    int gpio;
    int state;
    struct work_struct key_work;  // 慢路径工作任务
};

// 慢路径：工作队列函数（进程上下文，可执行慢操作）
static void key_work_func(struct work_struct *work)
{
    struct key_data *data = container_of(work, struct key_data, key_work);
    // 执行慢操作：日志打印+用户态通知
    dev_info(&data->dev->dev, "key state: %d\n", data->state);
    sysfs_notify(&data->dev->dev.kobj, NULL, "state");
}

// 快路径：中断处理函数（仅执行快操作）
static irqreturn_t key_irq_handler(int irq, void *dev_id)
{
    struct key_data *data = dev_id;
    // 快操作：读取GPIO状态+缓存到私有数据（总耗时<50us）
    data->state = gpio_get_value(data->gpio);
    // 提交慢任务到工作队列，立即退出中断
    queue_work(system_wq, &data->key_work);
    return IRQ_HANDLED;
}

// probe函数：初始化工作任务
static int key_probe(struct platform_device *pdev)
{
    struct key_data *data = devm_kzalloc(&pdev->dev, sizeof(*data), GFP_KERNEL);
    int ret;

    data->dev = &pdev->dev;
    data->gpio = of_get_named_gpio(pdev->dev.of_node, "gpio", 0);
    INIT_WORK(&data->key_work, key_work_func);  // 初始化工作任务

    // 申请中断
    ret = devm_request_irq(&pdev->dev, gpio_to_irq(data->gpio),
                           key_irq_handler, IRQF_TRIGGER_RISING_FALLING,
                           "key-irq", data);
    return ret;
}
